// ─── TICKET SCREEN COMPONENT ──────────────────────────────────────────────────
function TicketScreen({ comprobante, onBack, G, S }) {
  const [status, setStatus] = useState("idle");
  const [publicUrl, setPublicUrl] = useState("");
  const [copied, setCopied] = useState(false);
  const [view, setView] = useState("preview");

  const generarLink = async () => {
    setStatus("uploading");
    try {
      // Remove base64 logo (saves ~40KB) and minify whitespace
      const htmlLigero = comprobante.html
        .replace(/<img[^>]*src="data:image\/[^"]*"[^>]*\/?>/gi,
          '<div style="width:80px;height:80px;border-radius:50%;background:#2d5a27;margin:0 auto 10px;display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:900;color:#fff">B</div>')
        .replace(/\n\s+/g, ' ')
        .replace(/\s{2,}/g, ' ');

      // Upload as plain text (not JSON) to avoid JSON size limits
      const resp = await fetch("https://brago-tickets.vercel.app/api/save", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          html: htmlLigero,
          nombre: comprobante.nombre,
          tel: comprobante.tel || ""
        })
      });

      if (!resp.ok) {
        const err = await resp.text().catch(() => "unknown");
        throw new Error(err.substring(0, 100));
      }
      const data = await resp.json();
      if (!data.url) throw new Error("Sin URL");
      // Convert blob URL to friendly ticket URL
      const blobUrl = data.url;
      const ticketId = blobUrl.split("/tickets/")[1]?.replace(".html","");
      const friendlyUrl = ticketId 
        ? `https://brago-tickets.vercel.app/t/${ticketId}`
        : blobUrl;
      setPublicUrl(friendlyUrl);
      setStatus("done");
    } catch(e) {
      setStatus("error");
    }
  };

  const copiarLink = () => {
    try {
      if (navigator.clipboard) {
        navigator.clipboard.writeText(publicUrl);
      } else {
        const el = document.createElement("textarea");
        el.value = publicUrl;
        el.style.cssText = "position:fixed;opacity:0";
        document.body.appendChild(el);
        el.select();
        document.execCommand("copy");
        document.body.removeChild(el);
      }
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    } catch(e) {}
  };

  const enviarWA = () => {
    if (!comprobante.tel) return;
    const waNum = comprobante.tel.replace(/[^0-9]/g, "");
    const link = publicUrl;
    const msg = encodeURIComponent(
      `¡Hola ${comprobante.nombre}! 🧉
` +
      `Te mando tu comprobante de *Brago* ✅

` +
      `——————————————

` +
      `📋 *Tu ticket:*
${link}

` +
      `Abrí el link para ver el detalle de tu compra 🌿
` +
      `y la guía de cómo curar y cuidar tu mate 🧉

` +
      `——————————————

` +
      `📸 *Conocé más de Brago:*
instagram.com/brago_mates

` +
      `——————————————

` +
      `¡Gracias por elegirnos! 💛
` +
      `Estamos para lo que necesites.

` +
      `_BRAGO | Hechos para acompañar tus mejores momentos. 🌿_`
    );
    window.open(`https://wa.me/54${waNum}?text=${msg}`, "_blank");
  };

  const abrirIG = () => {
    window.open("https://instagram.com/brago_mates", "_blank");
  };

  if (view === "full") {
    // Inject a script into the HTML to make links work by posting messages
    const htmlConLinks = comprobante.html.replace(
      '</body>',
      `<script>
        document.querySelectorAll('a[href]').forEach(a => {
          a.addEventListener('click', function(e) {
            e.preventDefault();
            window.parent.postMessage({type:'navigate',url:this.href}, '*');
          });
        });
      </script></body>`
    );
    return (
      <div style={{position:"fixed",inset:0,background:"#fff",zIndex:500,display:"flex",flexDirection:"column"}}
        ref={el => {
          if (el) {
            window.addEventListener('message', function handler(ev) {
              if (ev.data && ev.data.type === 'navigate' && ev.data.url) {
                window.open(ev.data.url, '_blank');
              }
            });
          }
        }}>
        <div style={{background:G.n900,padding:"12px 16px",display:"flex",alignItems:"center",gap:12,flexShrink:0}}>
          <button onClick={()=>setView("preview")} style={{background:"none",border:"none",color:"#495057",cursor:"pointer",fontSize:15,fontFamily:"inherit",fontWeight:600}}>← Volver</button>
          <span style={{color:"#212529",fontWeight:700,fontSize:14,flex:1,textAlign:"center"}}>Ticket · {comprobante.nombre}</span>
        </div>
        <iframe srcDoc={htmlConLinks} style={{flex:1,border:"none",width:"100%"}} title="Ticket"
          sandbox="allow-scripts allow-same-origin allow-popups allow-popups-to-escape-sandbox"/>
      </div>
    );
  }

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
        <button onClick={onBack} style={{background:"none",border:"none",color:"#868e96",cursor:"pointer",fontSize:20,padding:0}}>←</button>
        <div style={{fontSize:16,fontWeight:700,color:G.white}}>Ticket generado</div>
      </div>

      <div style={{background:"linear-gradient(135deg,#1a2e1a,#2d5a27)",borderRadius:20,padding:24,textAlign:"center",marginBottom:16}}>
        <div style={{fontSize:48,marginBottom:8}}>🧾</div>
        <div style={{fontSize:20,fontWeight:800,color:"#fff",marginBottom:4}}>{comprobante.nombre}</div>
        <div style={{fontSize:12,color:"rgba(255,255,255,0.5)"}}>Ticket listo</div>
      </div>

      <button onClick={()=>setView("full")} style={{...S.btnPrimary,marginBottom:10,background:G.n700,border:`1px solid ${G.n600}`}}>
        👁 Previsualizar ticket
      </button>

      {status==="idle" && (
        <button onClick={generarLink} style={{...S.btnPrimary,marginBottom:10,background:G.g700}}>
          🔗 Generar link del ticket
        </button>
      )}

      {status==="uploading" && (
        <div style={{background:G.g900,border:`1px solid ${G.g700}`,borderRadius:14,padding:20,textAlign:"center",marginBottom:10}}>
          <div style={{fontSize:24,marginBottom:6}}>⏳</div>
          <div style={{fontSize:13,color:"#2d6a4f",fontWeight:600}}>Subiendo ticket...</div>
          <div style={{fontSize:11,color:"#adb5bd",marginTop:4}}>Puede tardar unos segundos</div>
        </div>
      )}

      {status==="error" && (
        <div style={{background:"rgba(192,57,43,0.1)",border:`1px solid ${G.red}`,borderRadius:14,padding:16,marginBottom:10}}>
          <div style={{fontSize:13,color:G.red,marginBottom:4,fontWeight:600}}>No se pudo generar el link</div>
          <div style={{fontSize:11,color:"#868e96",marginBottom:10}}>
            Revisá tu conexión e intentá de nuevo. Si sigue fallando, usá "Previsualizar" y compartí desde Safari.
          </div>
          <div style={{display:"flex",gap:8}}>
            <button onClick={generarLink} style={{...S.btnPrimary,flex:1,fontSize:13}}>Reintentar</button>
            {comprobante.tel&&<button onClick={()=>{
              const waNum=comprobante.tel.replace(/[^0-9]/g,"");
              const msg=encodeURIComponent(`¡Hola ${comprobante.nombre}! 🧉

Te mando tu comprobante de *Brago* ✅

· · · · · 🌿 · · · · ·

📸 *Conocé más de Brago:*
instagram.com/brago_mates

· · · · · 🤎 · · · · ·

¡Gracias por elegirnos! 💛
Estamos para lo que necesites. 🧉

_BRAGO | Hechos para acompañar tus mejores momentos. 🌿_`);
              window.open(`https://wa.me/54${waNum}?text=${msg}`,"_blank");
            }} style={{...S.btnPrimary,flex:1,background:"#25D366",fontSize:13}}>
              💬 WA sin link
            </button>}
          </div>
        </div>
      )}

      {status==="done" && publicUrl && (
        <>
          <div style={{background:G.g900,border:`1px solid ${G.g600}`,borderRadius:14,padding:16,marginBottom:10}}>
            <div style={{fontSize:10,color:"#2d6a4f",fontWeight:700,letterSpacing:1.5,textTransform:"uppercase",marginBottom:8}}>🔗 Link del ticket</div>
            <div style={{fontSize:10,color:G.n200,wordBreak:"break-all",fontFamily:"monospace",background:G.n800,padding:"10px 12px",borderRadius:8,marginBottom:10,lineHeight:1.6}}>
              {publicUrl}
            </div>
            <button onClick={copiarLink} style={{...S.btnPrimary,fontSize:13,background:copied?G.g600:G.g700,marginBottom:0}}>
              {copied?"✓ ¡Copiado!":"📋 Copiar link"}
            </button>
          </div>

          {comprobante.tel&&(
            <button onClick={enviarWA} style={{...S.btnPrimary,background:"#25D366",marginBottom:10}}>
              💬 Enviar ticket por WhatsApp
            </button>
          )}

          <div style={{background:G.n800,borderRadius:12,padding:12,marginBottom:14}}>
            <div style={{fontSize:11,color:"#868e96",lineHeight:1.7}}>
              ✅ El cliente toca el link y ve el ticket completo<br/>
              ✅ Funciona en cualquier navegador y dispositivo<br/>
              ✅ Podés copiar el link y mandarlo por donde quieras
            </div>
          </div>
        </>
      )}

      <button onClick={onBack} style={S.btnGhost}>Volver al inicio</button>
    </div>
  );
}

// ─── COMPROBANTE WA COMPONENT ─────────────────────────────────────────────────
function ComprobanteWA({ comprobante }) {
  const waNum = (comprobante.tel||"").replace(/\D/g,"");
  
  const enviar = () => {
    // Open ticket directly
    const url = "data:text/html;charset=utf-8," + encodeURIComponent(comprobante.html);
    window.open(url,"_blank");
    // Open WA with number pre-filled - user sends from WA
    if(waNum) {
      setTimeout(()=>{ window.location.href=`whatsapp://send?phone=${waNum}`; },300);
    }
  };

  return (
    <button onClick={enviar}
      style={{width:"100%",background:"#25D366",color:"#fff",border:"none",borderRadius:12,
        padding:"14px 20px",fontSize:15,fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginBottom:8}}>
      💬 Abrir ticket y WhatsApp
    </button>
  );
}

// ─── STYLES ───────────────────────────────────────────────────────────────────
const S = {
  card: { background:G.white, border:"1px solid #e9ecef", borderRadius:16, padding:16, marginBottom:12,
    boxShadow:"0 2px 8px rgba(0,0,0,0.06)" },
  cardGreen: { background:"#f0fff4", border:"1px solid #b7e4c7", borderRadius:16, padding:16, marginBottom:12 },
  inp: { width:"100%", background:"#ffffff", border:"1.5px solid #dee2e6", borderRadius:12, color:"#212529",
    padding:"13px 16px", fontSize:16, outline:"none", boxSizing:"border-box", marginBottom:10, fontFamily:"inherit" },
  btnPrimary: { background:G.g700, color:"#ffffff", border:"none", borderRadius:14, padding:"15px 20px",
    fontSize:15, fontWeight:700, cursor:"pointer", width:"100%", fontFamily:"inherit",
    boxShadow:"0 4px 12px rgba(64,145,108,0.3)" },
  btnGhost: { background:G.white, color:"#495057", border:"1.5px solid #dee2e6", borderRadius:14,
    padding:"13px 20px", fontSize:14, cursor:"pointer", width:"100%", fontFamily:"inherit", marginTop:8 },
  label: { color:G.g700, fontSize:11, letterSpacing:1.5, textTransform:"uppercase", marginBottom:8, marginTop:18,
    display:"block", fontWeight:700 },
};

// ─── TICKET VIEWER ────────────────────────────────────────────────────────────
function TicketViewer() {
  const [html, setHtml] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const ticketId = params.get("t");
    if (!ticketId) { setLoading(false); return; }

    window.storage.get(ticketId, true)
      .then(r => { if (r?.value) setHtml(r.value); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const params = new URLSearchParams(window.location.search);
  if (!params.get("t")) return null;

  if (loading) return (
    <div style={{position:"fixed",inset:0,background:"#f2ede8",display:"flex",alignItems:"center",justifyContent:"center",zIndex:9999,flexDirection:"column",gap:16}}>
      <div style={{fontSize:48}}>🧾</div>
      <div style={{fontSize:16,fontWeight:700,color:"#2d5a27"}}>Cargando ticket...</div>
    </div>
  );

  if (!html) return (
    <div style={{position:"fixed",inset:0,background:"#f2ede8",display:"flex",alignItems:"center",justifyContent:"center",zIndex:9999,flexDirection:"column",gap:12,padding:32}}>
      <div style={{fontSize:48}}>😕</div>
      <div style={{fontSize:16,fontWeight:700,color:"#2d5a27"}}>Ticket no encontrado</div>
      <div style={{fontSize:13,color:"#9aa39a",textAlign:"center"}}>El link puede haber expirado o no está disponible</div>
    </div>
  );

  return (
    <div style={{position:"fixed",inset:0,zIndex:9999}}>
      <iframe srcDoc={html} style={{width:"100%",height:"100%",border:"none"}} title="Ticket Brago"/>
    </div>
  );
}

export default function BragoApp() {
  const [tab, setTab] = useState("inicio");
  const [activeProfile, setActiveProfile] = useState(1);
  const [catalog, setCatalog] = useState(INITIAL_CATALOG);
  const [sales, setSales] = useState([]);
  const [ferias, setFerias] = useState([]);
  const [gastos, setGastos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [currentFeria, setCurrentFeria] = useState({1:null,2:null});
  const [papeleria, setPapeleria] = useState([]);
  const [toast, setToast] = useState(null);

  // Catalog nav: level = cats | groups | subs | variants | colors
  const [catNav, setCatNav] = useState({ level:"cats", cat:null, group:null, sub:null, variant:null });

  // Modals
  const [showNewFeria, setShowNewFeria] = useState(false);
  const [showGasto, setShowGasto] = useState(false);
  const [showCombo, setShowCombo] = useState(false);
  const [showAddSub, setShowAddSub] = useState(false);
  const [showAddVariant, setShowAddVariant] = useState(false);
  const [showEditVariant, setShowEditVariant] = useState(null);
  const [showComprobante, setShowComprobante] = useState(null);
  const [showClientes, setShowClientes] = useState(false);
  const [showPapeleria, setShowPapeleria] = useState(false);

  // Forms
  const [saleMode, setSaleMode] = useState("catalog");
  const [carrito, setCarrito] = useState([]); // [{item, qty}]
  const [saleNav, setSaleNav] = useState({ catId:"", groupId:"", subId:"", variantId:"", color:"", virola:"", qty:"1" });
  const [bulkTotal, setBulkTotal] = useState("");
  const [feriaName, setFeriaName] = useState("");
  const [gastoForm, setGastoForm] = useState({ desc:"", cat:"Encomienda", monto:"" });
  const [newSubName, setNewSubName] = useState("");
  const [newVariant, setNewVariant] = useState({ name:"", cost:"", price:"", colors:"" });
  const [comboItems, setComboItems] = useState([{ itemId:"", qty:1 }]);
  const [comboExtras, setComboExtras] = useState([{ desc:"", cost:"" }]);
  const [comboPrecio, setComboPrecio] = useState("");

  // Cobranza
  const [cobrItems, setCobrItems] = useState([{ nombre:"", descripcion:"", precio:"", qty:1, fromCatalog:false }]);
  const [cobrDescPct, setCobrDescPct] = useState("");
  const [cobrDescMonto, setCobrDescMonto] = useState("");
  const [cobrMode, setCobrMode] = useState("pct");
  const [metodoPago, setMetodoPago] = useState("Efectivo");
  const [cobrClienteNombre, setCobrClienteNombre] = useState("");
  const [cobrClienteTel, setCobrClienteTel] = useState("");
  const [cobrNota, setCobrNota] = useState("");

  // iOS keyboard fix - fontSize:16 prevents zoom, this handles scroll
  useEffect(() => {
    const fix = (e) => {
      const el = e.target;
      if (el.tagName==='INPUT'||el.tagName==='TEXTAREA'||el.tagName==='SELECT') {
        setTimeout(()=>el.scrollIntoView({block:'center',behavior:'smooth'}),300);
      }
    };
    document.addEventListener('focusin', fix);
    return ()=>document.removeEventListener('focusin', fix);
  }, []);

  useEffect(() => {
    try {
      const s = localStorage.getItem(SK);
      if (s) {
        const d = JSON.parse(s);
        if (d.catalog) setCatalog(d.catalog);
        if (d.sales) setSales(d.sales);
        if (d.ferias) setFerias(d.ferias);
        if (d.gastos) setGastos(d.gastos);
        if (d.clientes) setClientes(d.clientes);
        if (d.currentFeria) setCurrentFeria(d.currentFeria);
        if (d.papeleria) setPapeleria(d.papeleria);
      }
    } catch {}
  }, []);

  useEffect(() => {
    try { localStorage.setItem(SK, JSON.stringify({ catalog, sales, ferias, gastos, clientes, currentFeria, papeleria })); } catch {}
  }, [catalog, sales, ferias, gastos, clientes, currentFeria, papeleria]);

  const showToast = (msg, type="ok") => { setToast({ msg, type }); setTimeout(() => setToast(null), 2500); };
  const profile = PROFILES.find(p => p.id === activeProfile);
  const cf = currentFeria[activeProfile];
  const activeFeria = ferias.find(f => f.id === cf);
  const activeFeriaSales = sales.filter(s => s.feriaId === cf && s.profileId === activeProfile);
  const allItems = flatAll(catalog);

  // ── Sale helpers ──
  const saleCat = catalog.find(c => c.id === saleNav.catId);
  const saleGroup = saleCat?.groups?.find(g => g.id === saleNav.groupId);
  const saleSubs = saleGroup ? saleGroup.subs : (saleCat && !saleCat.groups ? saleCat.subs : null);
  const saleSub = saleSubs?.find(s => s.id === saleNav.subId);
  // Get unique virola types for current sub
  const saleVirolasDisponibles = saleSub ? [...new Set((saleSub.variants||[]).map(v=>v.virola).filter(Boolean))] : [];
  // Filter variants by virola if selected
  const saleVariantsFiltered = saleSub ? (saleNav.virola ? (saleSub.variants||[]).filter(v=>v.virola===saleNav.virola) : (saleSub.variants||[]).filter(v=>!v.virola)) : [];
  const saleVariant = saleVariantsFiltered.find(v => v.id === saleNav.variantId);
  const saleColors = saleVariant?.colors || [];
  const selectedItem = saleNav.variantId ? allItems.find(i =>
    i.variantId === saleNav.variantId && (saleColors.length === 0 || i.color === saleNav.color)
  ) : null;

  const [showEditSale, setShowEditSale] = useState(null);
  const [showVentaComprobante, setShowVentaComprobante] = useState(null);
  const [vcNombre, setVcNombre] = useState("");
  const [vcTel, setVcTel] = useState("");
  const [vcMetodoPago, setVcMetodoPago] = useState("Efectivo");
  const [confirmDeleteSale, setConfirmDeleteSale] = useState(null);
  const [detalleSale, setDetalleSale] = useState(null);
  const [activeStatCard, setActiveStatCard] = useState(null);
  const [ventaSearch, setVentaSearch] = useState("");
  const [showFeriaResumen, setShowFeriaResumen] = useState(null);
  const [catalogSearch, setCatalogSearch] = useState("");
  const [pinInput, setPinInput] = useState("");
  const [pinError, setPinError] = useState(false);
  const [pinConfirm, setPinConfirm] = useState("");
  const [pinUnlocked, setPinUnlocked] = useState(!!sessionStorage.getItem("brago_session"));



  const registerSale = () => {
    if (!selectedItem) return showToast("Elegí un producto", "err");
    const qty = Number(saleNav.qty) || 1;
    const sale = {
      id: Date.now(), itemId: selectedItem.id, productName: selectedItem.name, qty,
      price: selectedItem.price, cost: selectedItem.cost,
      total: selectedItem.price * qty, profit: (selectedItem.price - selectedItem.cost) * qty,
      date: new Date().toISOString(), feriaId: cf, profileId: activeProfile,
    };
    setSales(prev => [...prev, sale]);
    setSaleNav(n => ({ ...n, variantId:"", color:"", qty:"1" }));
    // Ask if want comprobante
    setVcNombre(""); setVcTel(""); setShowVentaComprobante(sale);
  };

  const registerBulk = () => {
    const total = Number(bulkTotal);
    if (!total) return showToast("Ingresá el total", "err");
    setSales(prev => [...prev, {
      id: Date.now(), productId: null, productName: "Total del día", qty:1,
      price: total, cost: total*0.55, total, profit: total*0.45,
      date: new Date().toISOString(), feriaId: cf, profileId: activeProfile, isBulk: true,
    }]);
    setBulkTotal(""); showToast("Total registrado");
  };

  const startFeria = () => {
    if (!feriaName.trim()) return showToast("Escribí el nombre", "err");
    const today = new Date().toISOString().split("T")[0];
    const num = getFeriaNum(ferias, today);
    const f = { id:Date.now(), name:feriaName.trim(), startDate:today, active:true, numMes:num, profileId:activeProfile };
    setFerias(prev => [...prev, f]);
    setCurrentFeria(prev => ({ ...prev, [activeProfile]: f.id }));
    setFeriaName(""); setShowNewFeria(false);
    crearICS(`Brago · Inicio — ${f.name}`, today, "09:00", `Feria N°${num} del mes · ${profile?.name}`);
    showToast(`Feria N°${num} iniciada`);
  };

  const closeFeria = () => {
    const today = new Date().toISOString().split("T")[0];
    const tv = activeFeriaSales.reduce((a,s) => a+s.total, 0);
    const gn = activeFeriaSales.reduce((a,s) => a+s.profit, 0);
    const gastosFeria = gastos.filter(g=>g.feriaId===cf||(!g.feriaId&&activeFeria));
    const gastoTotal = gastosFeria.reduce((a,g)=>a+g.monto,0);
    // Count product sales
    const prodCount = {};
    activeFeriaSales.forEach(s=>{ prodCount[s.productName]=(prodCount[s.productName]||0)+s.qty; });
    const topProductos = Object.entries(prodCount).sort((a,b)=>b[1]-a[1]).slice(0,5);
    const ticketProm = activeFeriaSales.length>0 ? Math.round(tv/activeFeriaSales.length) : 0;
    setShowFeriaResumen({ name:activeFeria.name, tv, gn, gastoTotal, neto:gn-gastoTotal, topProductos, ticketProm, count:activeFeriaSales.length, today, feria:activeFeria });
  };

  const confirmarCierreFeria = (today, feria, tv, gn) => {
    setFerias(prev => prev.map(f => f.id===cf ? { ...f, active:false, endDate:today } : f));
    setCurrentFeria(prev => ({ ...prev, [activeProfile]: null }));
    if (feria) crearICS(`Brago · Cierre — ${feria.name}`, today, "20:00",
      `N°${feria.numMes} · ${profile?.name}\nFacturación: ${fmt(tv)}\nGanancia: ${fmt(gn)}`);
    setShowFeriaResumen(null);
    showToast("Feria cerrada ✓");
  };

  const addGasto = () => {
    if (!gastoForm.desc || !gastoForm.monto) return showToast("Completá los campos", "err");
    setGastos(prev => [...prev, { id:Date.now(), ...gastoForm, monto:Number(gastoForm.monto), date:new Date().toISOString(), profileId:activeProfile }]);
    setGastoForm({ desc:"", cat:"Encomienda", monto:"" }); setShowGasto(false); showToast("Gasto registrado");
  };

  // Cobranza
  const cobrTotal = cobrItems.reduce((a,i) => a + (Number(i.precio)||0)*i.qty, 0);
  const cobrDescVal = cobrMode==="pct" ? Math.round(cobrTotal*(Number(cobrDescPct)||0)/100) : Number(cobrDescMonto)||0;
  const cobrFinal = cobrTotal - cobrDescVal;
  const cobrPctCalc = cobrTotal>0 ? Math.round((cobrDescVal/cobrTotal)*100) : 0;

  const generarYEnviar = () => {
    const nombreSnap = cobrClienteNombre.trim() || "Cliente";
    const tel = cobrClienteTel.trim();
    const itemsSnap = cobrItems.map(i=>({...i}));
    const notaSnap = cobrNota.trim();
    const descSnap = cobrDescVal;
    const totalSnap = cobrFinal;

    // ── Registrar la venta ──
    const totalCost = carrito.filter(c=>!c.libre).reduce((a,c)=>a+c.item.cost*c.qty, 0);
    const nombreVenta = itemsSnap.map(i=>i.nombre).filter(Boolean).join(", ") || "Cobro";
    setSales(prev => [...prev, {
      id: Date.now(),
      productName: nombreVenta,
      qty: itemsSnap.reduce((a,i)=>a+i.qty, 0),
      price: totalSnap,
      cost: totalCost,
      total: totalSnap,
      profit: totalSnap - totalCost,
      date: new Date().toISOString(),
      feriaId: cf,
      profileId: activeProfile,
      clienteNombre: nombreSnap,
      clienteTel: tel,
      metodoPago,
      nota: notaSnap,
    }]);

    // ── Guardar cliente ──
    const nuevaCompra = { fecha:new Date().toISOString(), items:itemsSnap, total:totalSnap, descuento:descSnap };
    const existente = clientes.find(c => c.tel===tel && tel!=="");
    if (existente) {
      setClientes(prev => prev.map(c => c.id===existente.id ? { ...c, compras:[...(c.compras||[]), nuevaCompra] } : c));
    } else if (nombreSnap !== "Cliente" || tel) {
      setClientes(prev => [...prev, { id:Date.now(), nombre:nombreSnap, tel, compras:[nuevaCompra] }]);
    }

    // ── Generar comprobante ──
    const html = generarComprobante({ items:itemsSnap, descuento:descSnap, metodoPago }, { nombre:nombreSnap }, LOGO_B64);
    setShowComprobante({ html, tel, nombre:nombreSnap });
    setCarrito([]);
    setTab("ticket");

    setTimeout(()=>{
      setCobrItems([{nombre:"",descripcion:"",precio:"",qty:1}]);
      setCobrClienteNombre(""); setCobrClienteTel("");
    }, 100);
    showToast("Comprobante generado ✓");
  };

  // Stats
  const now = new Date();
  const profSales = sales.filter(s => s.profileId === activeProfile);
  const todaySales = profSales.filter(s => new Date(s.date).toDateString() === now.toDateString());
  const weekStart = new Date(now); weekStart.setDate(now.getDate() - now.getDay());
  const weekSales = profSales.filter(s => new Date(s.date) >= weekStart);
  const monthSales = profSales.filter(s => new Date(s.date).getMonth()===now.getMonth() && new Date(s.date).getFullYear()===now.getFullYear());
  const monthGastos = gastos.filter(g => new Date(g.date).getMonth()===now.getMonth() && new Date(g.date).getFullYear()===now.getFullYear());
  const totalOf = arr => arr.reduce((a,s) => a+s.total, 0);
  const profitOf = arr => arr.reduce((a,s) => a+s.profit, 0);
  const feriaStats = ferias.map(f => { const fs=sales.filter(s=>s.feriaId===f.id&&s.profileId===f.profileId); return{...f,total:totalOf(fs),profit:profitOf(fs),count:fs.length}; });
  const comboCosto = () => comboItems.reduce((a,i)=>{const it=allItems.find(x=>x.id===i.itemId);return a+(it?it.cost*i.qty:0);},0) + comboExtras.reduce((a,e)=>a+(Number(e.cost)||0),0);
  const comboGan = () => Number(comboPrecio) - comboCosto();
  const comboMgn = () => Number(comboPrecio)>0 ? Math.round((comboGan()/Number(comboPrecio))*100) : 0;

  // ── UI helpers ──
  const Modal = ({ onClose, title, children }) => (
    <div style={{ position:"fixed", top:0, left:0, right:0, bottom:0, background:"#f8f9fa", zIndex:200,
      display:"flex", flexDirection:"column", WebkitOverflowScrolling:"touch" }}>
      <div style={{ background:"#ffffff", padding:"14px 20px", display:"flex", alignItems:"center",
        gap:12, borderBottom:"1px solid #e9ecef", flexShrink:0 }}>
        <button onClick={onClose} style={{ background:"none", border:"none", color:"#868e96",
          cursor:"pointer", fontSize:20, padding:0, lineHeight:1, fontFamily:"inherit" }}>←</button>
        <div style={{ fontSize:16, fontWeight:700, color:"#212529", flex:1 }}>{title}</div>
      </div>
      <div style={{ padding:"20px 20px 60px", boxSizing:"border-box", flex:1, overflowY:"auto", WebkitOverflowScrolling:"touch" }}>
        {children}
      </div>
    </div>
  );

  const StatCard = ({ label, value, sub, color, sales, cardKey }) => (
    <div onClick={()=>setActiveStatCard({label,value,sub,sales,cardKey})}
      style={{ background:"#ffffff", border:"1px solid #e9ecef", borderRadius:16, padding:"16px 14px", boxShadow:"0 2px 8px rgba(0,0,0,0.05)", cursor:"pointer" }}>
      <div style={{ fontSize:10, color:"#868e96", letterSpacing:1.5, textTransform:"uppercase", marginBottom:10, fontWeight:600 }}>{label}</div>
      <div style={{ fontSize:20, fontWeight:800, color:color||"#212529", letterSpacing:-0.5 }}>{value}</div>
      {sub && <div style={{ fontSize:11, color:"#adb5bd", marginTop:4 }}>{sub} ›</div>}
    </div>
  );

  const TAB_ICONS = {
    inicio: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>,
    vender: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>,
    catalogo: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg>,
    ferias: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>,
    gastos: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>,
    stats: <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>,
  };
  const TabBtn = ({ id, label }) => (
    <button onClick={() => setTab(id)} style={{ flex:1, background:"none", border:"none", cursor:"pointer",
      display:"flex", flexDirection:"column", alignItems:"center", gap:4, padding:"8px 0" }}>
      <div style={{ width:34, height:34, borderRadius:10,
        background:tab===id?"#f0fff4":"transparent",
        display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.2s",
        color:tab===id?"#40916c":"#adb5bd" }}>
        {TAB_ICONS[id]}
      </div>
      <span style={{ fontSize:9, color:tab===id?"#40916c":"#adb5bd", letterSpacing:0.5, fontWeight:tab===id?700:500 }}>{label}</span>
    </button>
  );

  const RowBtn = ({ onClick, title, sub, right }) => (
    <button onClick={onClick} style={{ width:"100%", background:"#ffffff", border:"1px solid #e9ecef",
      borderRadius:14, padding:"14px 16px", marginBottom:10, boxShadow:"0 1px 4px rgba(0,0,0,0.05)", display:"flex", alignItems:"center",
      justifyContent:"space-between", cursor:"pointer", fontFamily:"inherit", textAlign:"left" }}>
      <div>
        <div style={{ fontSize:14, fontWeight:600, color:"#212529" }}>{title}</div>
        {sub && <div style={{ fontSize:11, color:"#868e96", marginTop:2 }}>{sub}</div>}
      </div>
      <span style={{ color:"#adb5bd", fontSize:18 }}>{right||"›"}</span>
    </button>
  );

  const tabs = [
    { id:"inicio", label:"Inicio" },
    { id:"vender", label:"Vender" },
    { id:"catalogo", label:"Catálogo" },
    { id:"ferias", label:"Ferias" },
    { id:"gastos", label:"Gastos" },
    { id:"stats", label:"Stats" },
  ];

  const { level, cat:navCat, group:navGroup, sub:navSub, variant:navVariant } = catNav;

  const savedPin = localStorage.getItem("brago_pin")||"";
  const pinReady = savedPin.length===4;

  const onPinDigit = (d) => {
    if(pinInput.length>=4) return;
    const nx = pinInput+d;
    setPinInput(nx); setPinError(false);
    if(nx.length===4){
      if(!pinReady){
        if(!pinConfirm){ setPinConfirm(nx); setPinInput(""); }
        else if(nx===pinConfirm){ localStorage.setItem("brago_pin",nx); sessionStorage.setItem("brago_session","1"); setPinUnlocked(true); }
        else { setPinError(true); setPinInput(""); setPinConfirm(""); }
      } else {
        if(nx===savedPin){ sessionStorage.setItem("brago_session","1"); setPinUnlocked(true); }
        else { setPinError(true); setTimeout(()=>{ setPinInput(""); setPinError(false); },800); }
      }
    }
  };

  if(!pinUnlocked) return (
    <div style={{minHeight:"100vh",background:"#f8f9fa",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,fontFamily:"-apple-system,sans-serif"}}>
      <div style={{width:68,height:68,borderRadius:"50%",background:"linear-gradient(135deg,#2d6a4f,#40916c)",display:"flex",alignItems:"center",justifyContent:"center",marginBottom:20,boxShadow:"0 4px 20px rgba(64,145,108,0.35)"}}>
        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
      </div>
      <div style={{fontSize:24,fontWeight:800,color:"#1b4332",marginBottom:6,letterSpacing:3}}>BRAGO</div>
      <div style={{fontSize:13,color:"#868e96",marginBottom:36,textAlign:"center"}}>
        {!pinReady?(pinConfirm?"Confirmá tu PIN":"Creá un PIN de 4 dígitos"):"Ingresá tu PIN"}
      </div>
      <div style={{display:"flex",gap:18,marginBottom:36}}>
        {[0,1,2,3].map(i=>(
          <div key={i} style={{width:16,height:16,borderRadius:"50%",background:pinInput.length>i?(pinError?"#e03131":"#40916c"):"#dee2e6",transition:"all 0.2s"}}/>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,width:"100%",maxWidth:280}}>
        {[1,2,3,4,5,6,7,8,9].map(d=>(
          <button key={d} onClick={()=>onPinDigit(String(d))}
            style={{height:68,borderRadius:16,border:"1.5px solid #dee2e6",background:"#fff",fontSize:24,fontWeight:600,color:"#212529",cursor:"pointer",fontFamily:"inherit",boxShadow:"0 2px 6px rgba(0,0,0,0.06)"}}>
            {d}
          </button>
        ))}
        <div/>
        <button onClick={()=>onPinDigit("0")} style={{height:68,borderRadius:16,border:"1.5px solid #dee2e6",background:"#fff",fontSize:24,fontWeight:600,color:"#212529",cursor:"pointer",fontFamily:"inherit",boxShadow:"0 2px 6px rgba(0,0,0,0.06)"}}>0</button>
        <button onClick={()=>setPinInput(p=>p.slice(0,-1))} style={{height:68,borderRadius:16,border:"1.5px solid #dee2e6",background:"#fff",fontSize:20,color:"#868e96",cursor:"pointer",fontFamily:"inherit",boxShadow:"0 2px 6px rgba(0,0,0,0.06)"}}>⌫</button>
      </div>
      {pinError&&<div style={{marginTop:20,fontSize:13,color:"#e03131",fontWeight:600}}>PIN incorrecto</div>}
      {pinReady&&<button onClick={()=>{localStorage.removeItem("brago_pin");setPinInput("");setPinConfirm("");}} style={{marginTop:24,background:"none",border:"none",color:"#adb5bd",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>¿Olvidaste tu PIN? (resetear)</button>}
    </div>
  );

  return (
    <div style={{ background:"#f8f9fa", minHeight:"100vh", maxWidth:420, margin:"0 auto",
      fontFamily:"-apple-system, 'SF Pro Display', Georgia, serif", color:"#212529", paddingBottom:90 }}>
      <TicketViewer/>

      {/* STAT DETAIL OVERLAY */}
      {activeStatCard && (
        <div style={{position:"fixed",inset:0,background:"#f8f9fa",zIndex:500,display:"flex",flexDirection:"column",paddingBottom:80}}>
          <div style={{background:"#ffffff",padding:"14px 16px",display:"flex",alignItems:"center",gap:12,borderBottom:"1px solid #e9ecef",flexShrink:0}}>
            <button onClick={()=>setActiveStatCard(null)} style={{background:"none",border:"none",color:"#868e96",cursor:"pointer",fontSize:20,padding:0,lineHeight:1}}>←</button>
            <span style={{fontWeight:700,fontSize:16,color:"#212529",flex:1}}>{activeStatCard.label}</span>
            <span style={{fontSize:20,fontWeight:800,color:"#40916c"}}>{activeStatCard.value}</span>
          </div>
          <div style={{flex:1,overflowY:"auto",padding:"16px"}}>
            <div style={{background:"#ffffff",borderRadius:16,padding:16,boxShadow:"0 2px 8px rgba(0,0,0,0.05)"}}>
              {(!activeStatCard.sales||activeStatCard.sales.length===0)?(
                <div style={{fontSize:14,color:"#adb5bd",textAlign:"center",padding:"40px 0"}}>Sin ventas en este período</div>
              ):activeStatCard.sales.slice().reverse().map((s,i)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 0",borderBottom:"1px solid #f0f0f0"}}>
                  <div style={{flex:1,minWidth:0,marginRight:12}}>
                    <div style={{fontSize:13,fontWeight:600,color:"#212529",lineHeight:1.3}}>{s.productName}</div>
                    <div style={{fontSize:11,color:"#adb5bd",marginTop:2}}>{fechaL(s.date)} · {new Date(s.date).toLocaleTimeString("es-AR",{hour:"2-digit",minute:"2-digit"})}</div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0}}>
                    <div style={{fontSize:14,fontWeight:700,color:"#212529"}}>{fmt(s.total)}</div>
                    <div style={{fontSize:11,color:"#2d6a4f"}}>+{fmt(s.profit)}</div>
                  </div>
                </div>
              ))}
              {activeStatCard.sales&&activeStatCard.sales.length>0&&(
                <div style={{display:"flex",justifyContent:"space-between",padding:"14px 0 2px",borderTop:"2px solid #e9ecef",marginTop:4}}>
                  <span style={{fontSize:14,fontWeight:700,color:"#212529"}}>Total período</span>
                  <span style={{fontSize:16,fontWeight:800,color:"#40916c"}}>{fmt(activeStatCard.sales.reduce((a,s)=>a+s.total,0))}</span>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* RESUMEN CIERRE FERIA */}
      {showFeriaResumen && (
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:600,display:"flex",alignItems:"flex-end"}}>
          <div style={{background:"#fff",borderRadius:"24px 24px 0 0",padding:"24px 20px 40px",width:"100%",maxHeight:"90vh",overflowY:"auto"}}>
            <div style={{width:36,height:4,background:"#dee2e6",borderRadius:2,margin:"0 auto 20px"}}/>
            <div style={{textAlign:"center",marginBottom:20}}>
              <div style={{fontSize:32,marginBottom:8}}>🎉</div>
              <div style={{fontSize:20,fontWeight:800,color:"#1b4332"}}>¡Feria cerrada!</div>
              <div style={{fontSize:13,color:"#868e96",marginTop:4}}>{showFeriaResumen.name}</div>
            </div>
            {/* Stats grid */}
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
              {[
                {l:"Facturación",v:fmt(showFeriaResumen.tv),c:"#212529"},
                {l:"Ganancia bruta",v:fmt(showFeriaResumen.gn),c:"#40916c"},
                {l:"Gastos",v:fmt(showFeriaResumen.gastoTotal),c:"#e03131"},
                {l:"Lo que me quedó",v:fmt(showFeriaResumen.neto),c:"#2d6a4f"},
                {l:"Ventas",v:showFeriaResumen.count,c:"#212529"},
                {l:"Ticket promedio",v:fmt(showFeriaResumen.ticketProm),c:"#40916c"},
              ].map((r,i)=>(
                <div key={i} style={{background:"#f8f9fa",borderRadius:12,padding:"12px 14px",border:"1px solid #e9ecef"}}>
                  <div style={{fontSize:9,color:"#868e96",textTransform:"uppercase",letterSpacing:1.2,marginBottom:4,fontWeight:600}}>{r.l}</div>
                  <div style={{fontSize:17,fontWeight:800,color:r.c}}>{r.v}</div>
                </div>
              ))}
            </div>
            {/* Top productos */}
            {showFeriaResumen.topProductos.length>0 && (
              <div style={{background:"#f0fff4",borderRadius:14,padding:"14px 16px",marginBottom:16,border:"1px solid #b7e4c7"}}>
                <div style={{fontSize:10,color:"#2d6a4f",fontWeight:700,letterSpacing:1.5,textTransform:"uppercase",marginBottom:12}}>🏆 Más vendidos</div>
                {showFeriaResumen.topProductos.map(([name,qty],i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"6px 0",borderBottom:i<showFeriaResumen.topProductos.length-1?"1px solid #d8f3dc":"none"}}>
                    <div style={{display:"flex",alignItems:"center",gap:8,flex:1,minWidth:0}}>
                      <div style={{width:20,height:20,borderRadius:"50%",background:["#40916c","#52b788","#74c69d","#95d5b2","#b7e4c7"][i],display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:700,color:"#fff",flexShrink:0}}>{i+1}</div>
                      <span style={{fontSize:12,color:"#212529",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{name}</span>
                    </div>
                    <span style={{fontSize:12,fontWeight:700,color:"#2d6a4f",flexShrink:0,marginLeft:8}}>{qty} u.</span>
                  </div>
                ))}
              </div>
            )}
            <button onClick={()=>confirmarCierreFeria(showFeriaResumen.today,showFeriaResumen.feria,showFeriaResumen.tv,showFeriaResumen.gn)}
              style={{...S.btnPrimary,background:"#40916c",marginBottom:10}}>
              Confirmar cierre
            </button>
            <button onClick={()=>setShowFeriaResumen(null)} style={{...S.btnGhost}}>
              Volver a la feria
            </button>
          </div>
        </div>
      )}

      {/* TOAST */}
      {toast && <div style={{ position:"fixed", top:24, left:"50%", transform:"translateX(-50%)",
        background:toast.type==="err"?"#ffffff":"#40916c",
        color:toast.type==="err"?"#e03131":"#ffffff",
        border:toast.type==="err"?"1.5px solid #e03131":"none",
        boxShadow:toast.type==="err"?"0 4px 20px rgba(224,49,49,0.15)":"0 4px 20px rgba(0,0,0,0.2)",
        padding:"10px 22px", borderRadius:30, fontSize:13, zIndex:999, fontWeight:700,
        whiteSpace:"nowrap", letterSpacing:0.3 }}>{toast.msg}</div>}

      {/* HEADER */}
      <div style={{ background:"#ffffff",
        padding:"16px 20px", display:"flex", alignItems:"center", justifyContent:"space-between", borderBottom:"1px solid #e9ecef" }}>
        <div>
          <div style={{ fontSize:26, fontWeight:800, letterSpacing:4, color:"#1b4332" }}>BRAGO</div>
          <div style={{ fontSize:11, color:activeFeria?"#40916c":"#adb5bd", marginTop:2 }}>
            {activeFeria ? `● ${activeFeria.name}` : "Sin feria activa"}
          </div>
        </div>
        <div style={{ display:"flex", gap:8 }}>
          {PROFILES.map(p => (
            <button key={p.id} onClick={() => setActiveProfile(p.id)} style={{
              padding:"6px 14px", borderRadius:20, fontFamily:"inherit", fontSize:12, fontWeight:700, cursor:"pointer",
              border:`1.5px solid ${activeProfile===p.id ? G.g700 : "#dee2e6"}`,
              background:activeProfile===p.id ? G.g700 : "#f1f3f5",
              color:activeProfile===p.id ? "#ffffff" : "#868e96" }}>
              {p.name}
            </button>
          ))}
        </div>
      </div>

      <div style={{ padding:"8px 16px" }}>

      {/* ══════ INICIO ══════ */}
      {tab==="inicio" && (
        <div>
          {activeFeria ? (
            <div style={{ background:`linear-gradient(135deg, #2d6a4f, #40916c)`, borderRadius:20,
              padding:20, marginBottom:16, position:"relative", overflow:"hidden" }}>
              <div style={{ position:"absolute", top:-20, right:-20, width:80, height:80,
                background:"rgba(255,255,255,0.05)", borderRadius:"50%" }}/>
              <div style={{ fontSize:10, color:"#40916c", letterSpacing:2, textTransform:"uppercase", marginBottom:6 }}>
                Feria activa · {profile?.name}
              </div>
              <div style={{ fontSize:20, fontWeight:700, color:"#ffffff" }}>{activeFeria.name}</div>
              <div style={{ fontSize:11, color:"rgba(255,255,255,0.75)", marginBottom:16 }}>N°{activeFeria.numMes} · {fechaL(activeFeria.startDate)}</div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-end" }}>
                <div>
                  <div style={{ fontSize:28, fontWeight:800, color:"#ffffff" }}>{fmt(totalOf(activeFeriaSales))}</div>
                  <div style={{ fontSize:11, color:"rgba(255,255,255,0.75)" }}>{activeFeriaSales.length} ventas registradas</div>
                </div>
                <div style={{ display:"flex", gap:8 }}>
                  <button onClick={() => setTab("vender")} style={{ background:G.white, color:G.g700,
                    border:"none", borderRadius:10, padding:"8px 16px", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
                    + Venta
                  </button>
                  <button onClick={closeFeria} style={{ background:"rgba(0,0,0,0.2)", color:G.g200,
                    border:`1px solid ${G.g500}`, borderRadius:10, padding:"8px 14px", fontSize:13, cursor:"pointer", fontFamily:"inherit" }}>
                    Cerrar
                  </button>
                </div>
              </div>
            </div>
          ) : (
            <div style={{ background:G.n800, border:`1px solid ${G.n700}`, borderRadius:20, padding:20,
              marginBottom:16, textAlign:"center" }}>
              <div style={{ fontSize:11, color:profile?.color, fontWeight:700, letterSpacing:2, textTransform:"uppercase", marginBottom:10 }}>
                {profile?.name}
              </div>
              <div style={{ fontSize:13, color:"#868e96", marginBottom:14 }}>Sin feria activa</div>
              <button onClick={() => setShowNewFeria(true)} style={{ ...S.btnPrimary }}>
                Iniciar feria
              </button>
            </div>
          )}

          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
            <StatCard label="Hoy" value={fmt(totalOf(todaySales))} sub={`${todaySales.length} ventas`} color="#212529" sales={todaySales} cardKey="hoy"/>
            <StatCard label="Ganancia hoy" value={fmt(profitOf(todaySales))} sub={`${totalOf(todaySales)>0?Math.round(profitOf(todaySales)/totalOf(todaySales)*100):0}% margen`} color="#40916c" sales={todaySales} cardKey="ganHoy"/>
            <StatCard label="Esta semana" value={fmt(totalOf(weekSales))} sub={`${weekSales.length} ventas`} color="#212529" sales={weekSales} cardKey="semana"/>
            <StatCard label="Neto del mes" value={fmt(profitOf(monthSales)-monthGastos.filter(g=>g.profileId===activeProfile).reduce((a,g)=>a+g.monto,0))} sub="ganancia − gastos" color="#40916c" sales={monthSales} cardKey="mes"/>
          </div>

          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
            <button onClick={() => setTab("cobrar")} style={{ background:G.g700, border:"none",
              borderRadius:14, padding:"14px", cursor:"pointer", fontFamily:"inherit", textAlign:"left" }}>
              <div style={{ fontSize:18, marginBottom:6 }}>🧾</div>
              <div style={{ fontSize:13, fontWeight:700, color:"#ffffff" }}>Generar</div>
              <div style={{ fontSize:11, color:"rgba(255,255,255,0.75)" }}>comprobante</div>
            </button>
            <button onClick={() => setShowClientes(true)} style={{ background:G.n800, border:`1px solid ${G.n700}`,
              borderRadius:14, padding:"14px", cursor:"pointer", fontFamily:"inherit", textAlign:"left" }}>
              <div style={{ fontSize:18, marginBottom:6 }}>👥</div>
              <div style={{ fontSize:13, fontWeight:700, color:"#212529" }}>Clientes</div>
              <div style={{ fontSize:11, color:"#868e96" }}>{clientes.length} guardados</div>
            </button>
          </div>

          {profSales.length > 0 && <>
            <div style={{ fontSize:10, color:"#868e96", letterSpacing:2, textTransform:"uppercase", marginBottom:10, fontWeight:600 }}>Últimas ventas</div>
            {profSales.slice(-4).reverse().map(s => (
              <div key={s.id} style={{ ...S.card, display:"flex", justifyContent:"space-between",
                alignItems:"center", padding:"12px 14px" }}>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:12, fontWeight:600, overflow:"hidden", textOverflow:"ellipsis",
                    whiteSpace:"nowrap", color:"#212529" }}>{s.productName}</div>
                  <div style={{ fontSize:11, color:"#adb5bd", marginTop:2 }}>
                    {new Date(s.date).toLocaleTimeString("es-AR",{hour:"2-digit",minute:"2-digit"})} · {s.qty} u.
                  </div>
                </div>
                <div style={{ textAlign:"right", marginLeft:10, flexShrink:0 }}>
                  <div style={{ fontSize:14, fontWeight:700, color:"#212529" }}>{fmt(s.total)}</div>
                  <div style={{ fontSize:11, color:"#2d6a4f" }}>+{fmt(s.profit)}</div>
                </div>
              </div>
            ))}
          </>}
        </div>
      )}

      {/* ══════ VENDER ══════ */}
      {tab==="vender" && (
        <div>
          <div style={{fontSize:10,color:"#868e96",letterSpacing:2,textTransform:"uppercase",marginBottom:14,fontWeight:600}}>
            Registrar venta · {profile?.name}
          </div>

          {/* ── SELECTOR DE PRODUCTO ── */}
          <div style={{...S.card,marginBottom:12}}>
            <div style={{fontSize:11,color:"#40916c",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:12}}>Agregar producto</div>

            {/* Barra de búsqueda */}
            <div style={{position:"relative",marginBottom:12}}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#adb5bd" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
                style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",pointerEvents:"none"}}>
                <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
              </svg>
              <input value={catalogSearch} onChange={e=>{setCatalogSearch(e.target.value); if(e.target.value) setSaleNav({catId:"",groupId:"",subId:"",variantId:"",color:"",virola:"",qty:"1"});}}
                placeholder="Buscar producto..."
                style={{width:"100%",background:"#f8f9fa",border:"1.5px solid #dee2e6",borderRadius:12,padding:"11px 36px 11px 36px",fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:"inherit",color:"#212529"}}/>
              {catalogSearch&&<button onClick={()=>setCatalogSearch("")} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:"#adb5bd",cursor:"pointer",fontSize:18,padding:0}}>×</button>}
            </div>

            {/* Resultados de búsqueda */}
            {catalogSearch && (
              <div style={{marginBottom:12}}>
                {allItems.filter(i=>{
                  const words = catalogSearch.toLowerCase().trim().split(/\s+/);
                  const name = i.name.toLowerCase();
                  return words.every(w=>name.includes(w));
                }).slice(0,8).map(item=>(
                  <div key={item.id} onClick={()=>{
                    setSaleNav(n=>({...n,variantId:item.variantId,color:item.color||"",catId:"search"}));
                    setCatalogSearch("");
                    setCarrito(prev=>[...prev,{item,qty:1}]);
                    showToast("Agregado al carrito ✓");
                  }} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 12px",borderRadius:10,border:"1px solid #e9ecef",background:"#fff",marginBottom:6,cursor:"pointer"}}>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:12,fontWeight:600,color:"#212529",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.name}</div>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
                      <span style={{fontSize:13,fontWeight:700,color:"#40916c"}}>{fmt(item.price)}</span>
                      <span style={{fontSize:18,color:"#40916c",fontWeight:700}}>+</span>
                    </div>
                  </div>
                ))}
                {allItems.filter(i=>{
                  const words=catalogSearch.toLowerCase().trim().split(/\s+/);
                  const name=i.name.toLowerCase();
                  return words.every(w=>name.includes(w));
                }).length===0&&(
                  <div style={{fontSize:13,color:"#adb5bd",textAlign:"center",padding:"12px 0"}}>Sin resultados</div>
                )}
              </div>
            )}

            {!catalogSearch && <>
            <span style={S.label}>Categoría</span>
            <select value={saleNav.catId} onChange={e=>setSaleNav({catId:e.target.value,groupId:"",subId:"",variantId:"",color:"",virola:"",qty:"1"})} style={{...S.inp,appearance:"none"}}>
              <option value="">— Elegí —</option>
              {catalog.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

            {saleCat?.groups && <>
              <span style={S.label}>Grupo</span>
              <select value={saleNav.groupId} onChange={e=>setSaleNav(n=>({...n,groupId:e.target.value,subId:"",variantId:"",color:"",virola:""}))} style={{...S.inp,appearance:"none"}}>
                <option value="">— Elegí —</option>
                {saleCat.groups.map(g=><option key={g.id} value={g.id}>{g.name}</option>)}
              </select>
            </>}

            {saleSubs && <>
              <span style={S.label}>Subgrupo</span>
              <select value={saleNav.subId} onChange={e=>setSaleNav(n=>({...n,subId:e.target.value,variantId:"",color:"",virola:""}))} style={{...S.inp,appearance:"none"}}>
                <option value="">— Elegí —</option>
                {saleSubs.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </>}

            {saleSub && saleVirolasDisponibles.length > 0 && <>
              <span style={S.label}>Virola</span>
              <div style={{display:"flex",gap:8,marginBottom:14}}>
                {saleVirolasDisponibles.map(v=>(
                  <button key={v} onClick={()=>setSaleNav(n=>({...n,virola:v,variantId:"",color:""}))}
                    style={{flex:1,padding:"11px",borderRadius:12,
                      border:`1.5px solid ${saleNav.virola===v?"#40916c":"#dee2e6"}`,
                      background:saleNav.virola===v?"#40916c":"#ffffff",
                      color:saleNav.virola===v?"#ffffff":"#495057",
                      cursor:"pointer",fontFamily:"inherit",fontSize:14,fontWeight:saleNav.virola===v?700:500}}>
                    {v}
                  </button>
                ))}
              </div>
            </>}

            {saleSub && (saleNav.virola || saleVirolasDisponibles.length===0) && saleVariantsFiltered.length > 0 && <>
              <span style={S.label}>Modelo</span>
              <select value={saleNav.variantId} onChange={e=>setSaleNav(n=>({...n,variantId:e.target.value,color:""}))} style={{...S.inp,appearance:"none"}}>
                <option value="">— Elegí —</option>
                {saleVariantsFiltered.map(v=><option key={v.id} value={v.id}>{v.name} · {fmt(v.price)}</option>)}
              </select>
            </>}

            {saleVariant && saleColors.length>0 && <>
              <span style={S.label}>Color</span>
              <div style={{display:"flex",flexWrap:"wrap",gap:8,marginBottom:14}}>
                {saleColors.map(color=>(
                  <button key={color} onClick={()=>setSaleNav(n=>({...n,color}))}
                    style={{display:"flex",alignItems:"center",gap:8,padding:"8px 14px",borderRadius:10,
                      border:`1.5px solid ${saleNav.color===color?"#40916c":"#dee2e6"}`,
                      background:saleNav.color===color?"#f0fff4":"#fff",cursor:"pointer",fontFamily:"inherit"}}>
                    <div style={{width:14,height:14,borderRadius:"50%",background:{"Negro":"#1c1c1c","Borravino":"#6b1a2b","Chocolate":"#5c3317","Marrón":"#8B4513","Natural":"#c8a96e","Blanco":"#e8e8e8","Rosa":"#e8789a","Suecia":"#b8955a"}[color]||"#888",border:"1.5px solid rgba(0,0,0,0.1)",flexShrink:0}}/>
                    <span style={{fontSize:13,color:saleNav.color===color?"#2d6a4f":"#495057",fontWeight:saleNav.color===color?700:400}}>{color}</span>
                  </button>
                ))}
              </div>
            </>}

            {selectedItem && (
              <div style={{background:"#f0fff4",borderRadius:10,padding:"10px 14px",marginBottom:12,display:"flex",justifyContent:"space-between"}}>
                <span style={{fontSize:12,color:"#495057"}}>{selectedItem.name.split(" · ").slice(-2).join(" · ")}</span>
                <span style={{fontSize:13,fontWeight:700,color:"#2d6a4f"}}>{fmt(selectedItem.price)}</span>
              </div>
            )}

            <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:12}}>
              <span style={{color:"#868e96",fontSize:14}}>Cantidad:</span>
              <button onClick={()=>setSaleNav(n=>({...n,qty:Math.max(1,Number(n.qty)-1).toString()}))}
                style={{width:34,height:34,borderRadius:10,border:"1.5px solid #dee2e6",background:"#fff",color:"#212529",fontSize:18,cursor:"pointer"}}>−</button>
              <span style={{fontSize:20,fontWeight:800,minWidth:24,textAlign:"center",color:"#212529"}}>{saleNav.qty}</span>
              <button onClick={()=>setSaleNav(n=>({...n,qty:(Number(n.qty)+1).toString()}))}
                style={{width:34,height:34,borderRadius:10,border:"1.5px solid #dee2e6",background:"#fff",color:"#212529",fontSize:18,cursor:"pointer"}}>+</button>
            </div>

            </>}

            {!catalogSearch && <button onClick={()=>{
              if(!selectedItem) return showToast("Elegí un producto","err");
              const qty=Number(saleNav.qty)||1;
              setCarrito(prev=>[...prev,{item:selectedItem,qty}]);
              setSaleNav(n=>({...n,catId:"",groupId:"",subId:"",variantId:"",color:"",qty:"1"}));
              showToast("Agregado al carrito ✓");
            }} style={{...S.btnPrimary,background:"#52b788"}}>
              + Agregar al carrito
            </button>}

            {/* Cobro libre */}
            <button onClick={()=>{
              setCarrito(prev=>[...prev,{item:null,qty:1,libre:true,nombre:"",precio:""}]);
            }} style={{...S.btnGhost,marginTop:8,fontSize:13}}>
              + Producto personalizado
            </button>
          </div>

          {/* ── ITEMS LIBRES ── */}
          {carrito.filter(c=>c.libre).map((c,i)=>{
            const idx=carrito.indexOf(c);
            return (
              <div key={i} style={{...S.card,marginBottom:8}}>
                <input placeholder="Nombre del producto" value={c.nombre||""}
                  onChange={e=>{const n=[...carrito];n[idx]={...n[idx],nombre:e.target.value};setCarrito(n);}}
                  style={{...S.inp,marginBottom:6}}/>
                <div style={{display:"flex",gap:8}}>
                  <input type="number" placeholder="Precio $" value={c.precio||""}
                    onChange={e=>{const n=[...carrito];n[idx]={...n[idx],precio:e.target.value};setCarrito(n);}}
                    style={{...S.inp,marginBottom:0,flex:2}}/>
                  <div style={{display:"flex",alignItems:"center",gap:6,flex:1}}>
                    <button onClick={()=>{const n=[...carrito];n[idx]={...n[idx],qty:Math.max(1,n[idx].qty-1)};setCarrito(n);}}
                      style={{width:30,height:30,borderRadius:8,border:"1px solid #dee2e6",background:"#fff",fontSize:16,cursor:"pointer"}}>−</button>
                    <span style={{fontSize:14,fontWeight:700,minWidth:16,textAlign:"center"}}>{c.qty}</span>
                    <button onClick={()=>{const n=[...carrito];n[idx]={...n[idx],qty:n[idx].qty+1};setCarrito(n);}}
                      style={{width:30,height:30,borderRadius:8,border:"1px solid #dee2e6",background:"#fff",fontSize:16,cursor:"pointer"}}>+</button>
                  </div>
                  <button onClick={()=>setCarrito(carrito.filter((_,j)=>j!==idx))}
                    style={{background:"transparent",border:"1px solid #dee2e6",color:G.red,borderRadius:8,padding:"6px 10px",cursor:"pointer",fontSize:14}}>×</button>
                </div>
              </div>
            );
          })}

          {/* ── CARRITO ── */}
          {carrito.length>0 && (
            <div style={{...S.card,marginBottom:12}}>
              <div style={{fontSize:11,color:"#40916c",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:12}}>
                Carrito · {carrito.length} {carrito.length===1?"producto":"productos"}
              </div>
              {carrito.filter(c=>!c.libre).map((c,i)=>(
                <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid #f0f0f0"}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12,fontWeight:600,color:"#212529",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.item.name}</div>
                    <div style={{fontSize:11,color:"#868e96"}}>× {c.qty} · {fmt(c.item.price)} c/u</div>
                  </div>
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <span style={{fontSize:13,fontWeight:700,color:"#2d6a4f"}}>{fmt(c.item.price*c.qty)}</span>
                    <button onClick={()=>setCarrito(carrito.filter((_,j)=>j!==i))}
                      style={{background:"none",border:"none",color:"#adb5bd",cursor:"pointer",fontSize:16,padding:0}}>×</button>
                  </div>
                </div>
              ))}
              <div style={{display:"flex",justifyContent:"space-between",padding:"12px 0 0",marginTop:4}}>
                <span style={{fontSize:15,fontWeight:700,color:"#212529"}}>Total</span>
                <span style={{fontSize:18,fontWeight:800,color:"#40916c"}}>{fmt(carrito.reduce((a,c)=>a+(c.libre?(Number(c.precio)||0)*c.qty:c.item.price*c.qty),0))}</span>
              </div>
              <div style={{display:"flex",gap:8,marginTop:12}}>
                <button onClick={()=>{
                  const total=carrito.reduce((a,c)=>a+(c.libre?(Number(c.precio)||0)*c.qty:c.item.price*c.qty),0);
                  const cost=carrito.filter(c=>!c.libre).reduce((a,c)=>a+c.item.cost*c.qty,0);
                  const nombre=carrito.filter(c=>!c.libre).map(c=>c.item.name.split(" · ").pop()).join(", ")||"Cobro múltiple";
                  setSales(prev=>[...prev,{
                    id:Date.now(),productName:nombre,qty:carrito.reduce((a,c)=>a+c.qty,0),
                    price:total,cost,total,profit:total-cost,
                    date:new Date().toISOString(),feriaId:cf,profileId:activeProfile,
                    carritoItems:carrito.map(c=>c.libre?{nombre:c.nombre,precio:Number(c.precio)||0,qty:c.qty}:{nombre:c.item.name,precio:c.item.price,qty:c.qty})
                  }]);
                  setCarrito([]);
                  setCarrito([]);
                  showToast("Venta registrada ✓");
                }} style={{...S.btnPrimary,flex:1}}>Registrar</button>
                <button onClick={()=>{
                  // Pre-fill cobrar form with carrito items
                  const items = carrito.map(c=>c.libre
                    ? {nombre:c.nombre||"Producto",descripcion:"",precio:c.precio||"",qty:c.qty}
                    : {nombre:c.item.name,descripcion:"",precio:String(c.item.price),qty:c.qty}
                  );
                  setCobrItems(items.length>0?items:[{nombre:"",descripcion:"",precio:"",qty:1}]);
                  setTab("cobrar");
                }} style={{...S.btnPrimary,flex:1,background:"#52b788"}}>
                  🧾 Cobrar
                </button>
              </div>
              <button onClick={()=>setCarrito([])} style={{...S.btnGhost,marginTop:6,fontSize:12,color:G.red,borderColor:"#dee2e6"}}>
                Vaciar carrito
              </button>
            </div>
          )}

          <button onClick={()=>setShowCombo(true)} style={{...S.btnGhost,marginTop:8,fontSize:13,color:"#2d6a4f",borderColor:G.g700,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="3" width="20" height="14" rx="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>
            Calculadora de combos
          </button>
        </div>
      )}

      {/* ══════ CATÁLOGO ══════ */}
      {tab==="catalogo" && (
        <div>
          {/* Breadcrumb */}
          <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:14, flexWrap:"wrap" }}>
            {[
              { label:"Catálogo", action:()=>setCatNav({level:"cats",cat:null,group:null,sub:null,variant:null}), active:level==="cats" },
              navCat && { label:navCat.name, action:()=>setCatNav(n=>({...n,level:navCat.groups?"groups":"subs",group:null,sub:null,variant:null})), active:["groups","subs"].includes(level)&&!navGroup },
              navGroup && { label:navGroup.name, action:()=>setCatNav(n=>({...n,level:"subs",sub:null,variant:null})), active:level==="subs" },
              navSub && { label:navSub.name, action:()=>setCatNav(n=>({...n,level:"variants",variant:null})), active:level==="variants" },
              navVariant && { label:navVariant.name, action:null, active:true },
            ].filter(Boolean).map((item, i, arr) => (
              <span key={i} style={{ display:"flex", alignItems:"center", gap:6 }}>
                {i>0 && <span style={{ color:G.n600 }}>›</span>}
                <button onClick={item.action||undefined} style={{ background:"none", border:"none",
                  color:item.active?G.g400:G.n500, cursor:item.action?"pointer":"default",
                  fontSize:13, fontWeight:item.active?700:400, fontFamily:"inherit", padding:0 }}>
                  {item.label}
                </button>
              </span>
            ))}
          </div>

          {/* Papelería */}
          <div style={{ ...S.cardGreen, marginBottom:14, cursor:"pointer" }} onClick={()=>setShowPapeleria(true)}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <div style={{ fontSize:12, color:"#2d6a4f", fontWeight:700, marginBottom:2 }}>Costos de Papelería</div>
                <div style={{ fontSize:11, color:"#adb5bd" }}>{papeleria.length} ítems · {fmt(papeleria.reduce((a,p)=>a+(Number(p.costo)||0),0))} por venta</div>
              </div>
              <span style={{ color:G.n600 }}>›</span>
            </div>
          </div>

          {/* Categorías */}
          {level==="cats" && catalog.map(cat => {
            const total = cat.groups
              ? cat.groups.reduce((a,g)=>a+g.subs.reduce((b,s)=>b+(s.variants||[]).length,0),0)
              : (cat.subs||[]).reduce((a,s)=>a+(s.variants||[]).length,0);
            return <RowBtn key={cat.id} onClick={()=>setCatNav({level:cat.groups?"groups":"subs",cat,group:null,sub:null,variant:null})}
              title={cat.name} sub={`${total} variantes`}/>;
          })}

          {/* Grupos */}
          {level==="groups" && navCat?.groups && navCat.groups.map(g => {
            const total = g.subs.reduce((a,s)=>a+(s.variants||[]).length,0);
            return <RowBtn key={g.id} onClick={()=>setCatNav(n=>({...n,level:"subs",group:g,sub:null,variant:null}))}
              title={g.name} sub={`${total} variantes · ${g.subs.length} subgrupos`}/>;
          })}

          {/* Subgrupos */}
          {level==="subs" && (() => {
            const subs = navGroup ? navGroup.subs : (navCat?.subs||[]);
            return <>
              {subs.map(s => <RowBtn key={s.id} onClick={()=>setCatNav(n=>({...n,level:"variants",sub:s,variant:null}))}
                title={s.name} sub={`${(s.variants||[]).length} variantes`}/>)}
              <button onClick={()=>setShowAddSub(true)} style={{...S.btnGhost,marginTop:4}}>+ Nuevo subgrupo</button>
            </>;
          })()}

          {/* Variantes */}
          {level==="variants" && navSub && <>
            {(navSub.variants||[]).length===0 && <div style={{color:"#adb5bd",fontSize:14,textAlign:"center",marginTop:30}}>Sin variantes. Agregá la primera.</div>}
            {(navSub.variants||[]).map(v => (
              <div key={v.id} style={{ ...S.card, cursor:"pointer", marginBottom:10 }}
                onClick={() => { if(v.colors&&v.colors.length>0) setCatNav(n=>({...n,level:"colors",variant:v})); else setShowEditVariant({...v}); }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:14, fontWeight:700, color:"#212529", marginBottom:8 }}>{v.name}</div>
                    {v.colors && v.colors.length > 0 && (
                      <div style={{ display:"flex", gap:6, marginBottom:8 }}>
                        {v.colors.map(c => (
                          <div key={c} title={c} style={{ width:16, height:16, borderRadius:"50%",
                            background:COLOR_SWATCH[c]||"#888", border:"1.5px solid rgba(255,255,255,0.15)" }}/>
                        ))}
                      </div>
                    )}
                    <div style={{ display:"flex", gap:14 }}>
                      {[["Costo",fmt(v.cost),G.n400],["Venta",fmt(v.price),G.white],["Ganancia",fmt(v.price-v.cost),G.g400]].map(([l,val,col])=>(
                        <div key={l}>
                          <div style={{fontSize:9,color:G.n600,textTransform:"uppercase",letterSpacing:1}}>{l}</div>
                          <div style={{fontSize:13,color:col,fontWeight:700}}>{val}</div>
                        </div>
                      ))}
                    </div>
                  </div>
                  <div style={{ textAlign:"center", minWidth:44 }}>
                    <div style={{ fontSize:17, fontWeight:800, color:pct(v.cost,v.price)>=50?G.g400:pct(v.cost,v.price)>=35?G.amber:G.red }}>
                      {pct(v.cost,v.price)}%
                    </div>
                    <div style={{fontSize:9,color:G.n600}}>margen</div>
                  </div>
                </div>
                <div style={{fontSize:10,color:G.n600,marginTop:8}}>
                  {v.colors&&v.colors.length>0 ? `${v.colors.length} colores · tocá para ver` : "Tocá para editar"}
                </div>
              </div>
            ))}
            <button onClick={()=>setShowAddVariant(true)} style={{...S.btnPrimary,marginTop:4}}>+ Agregar variante</button>
          </>}

          {/* Colores de variante */}
          {level==="colors" && navVariant && <>
            <div style={{...S.cardGreen,marginBottom:14}}>
              <div style={{fontSize:14,fontWeight:700,color:"#212529",marginBottom:2}}>{navVariant.name}</div>
              <div style={{fontSize:12,color:G.n400}}>Costo: {fmt(navVariant.cost)} · Venta: {fmt(navVariant.price)}</div>
            </div>
            {navVariant.colors.map(color => (
              <div key={color} style={{...S.card,display:"flex",alignItems:"center",gap:14,marginBottom:8}}>
                <div style={{width:20,height:20,borderRadius:"50%",background:COLOR_SWATCH[color]||"#888",
                  border:"1.5px solid rgba(255,255,255,0.15)",flexShrink:0}}/>
                <span style={{fontSize:15,fontWeight:600,color:"#212529",flex:1}}>{color}</span>
                <span style={{fontSize:13,color:"#2d6a4f",fontWeight:700}}>{fmt(navVariant.price)}</span>
              </div>
            ))}
            <button onClick={()=>setShowEditVariant({...navVariant})} style={{...S.btnGhost,marginTop:8}}>Editar esta variante</button>
          </>}
        </div>
      )}

      {/* ══════ FERIAS ══════ */}
      {tab==="ferias" && (
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
            <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase"}}>Ferias · {profile?.name}</div>
            <button onClick={()=>setShowNewFeria(true)} style={{background:G.g700,color:"#212529",border:"none",borderRadius:8,padding:"6px 14px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>+ Nueva</button>
          </div>
          {feriaStats.filter(f=>f.profileId===activeProfile).length===0 && <div style={{color:"#adb5bd",fontSize:14,textAlign:"center",marginTop:40}}>Sin ferias registradas</div>}
          {feriaStats.filter(f=>f.profileId===activeProfile).slice().reverse().map(f=>(
            <div key={f.id} style={{...S.card,borderColor:f.active?G.g700:G.n700}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{fontSize:15,fontWeight:700,color:G.white}}>{f.active&&<span style={{color:G.g400}}>● </span>}{f.name}</div>
                  <div style={{fontSize:11,color:"#adb5bd",marginTop:2}}>N°{f.numMes} · {fechaL(f.startDate)}{f.endDate&&f.endDate!==f.startDate?` → ${fechaL(f.endDate)}`:""}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontSize:16,fontWeight:800,color:G.white}}>{fmt(f.total)}</div>
                  <div style={{fontSize:12,color:G.g400}}>+{fmt(f.profit)}</div>
                  <div style={{fontSize:11,color:G.n500}}>{f.count} ventas</div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ══════ GASTOS ══════ */}
      {tab==="gastos" && (
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
            <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase"}}>Gastos del mes</div>
            <button onClick={()=>setShowGasto(true)} style={{background:G.red,color:"#212529",border:"none",borderRadius:8,padding:"6px 14px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>+ Gasto</button>
          </div>
          {(() => {
            const mg=gastos.filter(g=>new Date(g.date).getMonth()===now.getMonth());
            const byCat=GASTO_CATS.map(cat=>({cat,total:mg.filter(g=>g.cat===cat).reduce((a,g)=>a+g.monto,0)})).filter(x=>x.total>0);
            const total=mg.reduce((a,g)=>a+g.monto,0);
            return byCat.length>0?(<div style={{...S.card,marginBottom:14}}>
              <div style={{fontSize:10,color:"#adb5bd",textTransform:"uppercase",letterSpacing:1.5,marginBottom:10}}>Por categoría</div>
              {byCat.map(x=>(<div key={x.cat} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${G.n700}`}}>
                <span style={{fontSize:13,color:G.n300}}>{x.cat}</span>
                <span style={{fontSize:13,fontWeight:700,color:G.red}}>{fmt(x.total)}</span>
              </div>))}
              <div style={{display:"flex",justifyContent:"space-between",padding:"10px 0 0"}}>
                <span style={{fontSize:14,fontWeight:700,color:G.white}}>Total</span>
                <span style={{fontSize:14,fontWeight:700,color:G.red}}>{fmt(total)}</span>
              </div>
            </div>):null;
          })()}
          {gastos.length===0&&<div style={{color:"#adb5bd",fontSize:14,textAlign:"center",marginTop:40}}>Sin gastos</div>}
          {gastos.slice().reverse().map(g=>(<div key={g.id} style={{...S.card,display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 14px",marginBottom:8}}>
            <div><div style={{fontSize:14,fontWeight:600,color:G.n100}}>{g.desc}</div><div style={{fontSize:11,color:G.n500}}>{g.cat} · {fechaL(g.date)}</div></div>
            <div style={{fontSize:15,fontWeight:700,color:G.red}}>{fmt(g.monto)}</div>
          </div>))}
        </div>
      )}

      {/* ══════ STATS ══════ */}
      {tab==="stats" && (
        <div>
          <div style={{...S.card,background:`linear-gradient(135deg,${G.g900},${G.g800})`,marginBottom:10}}>
            <div style={{fontSize:10,color:"rgba(255,255,255,0.6)",letterSpacing:2,textTransform:"uppercase",marginBottom:12}}>Resumen del mes · {profile?.name}</div>
            {[
              {l:"Facturación",v:fmt(totalOf(monthSales))},
              {l:"Ganancia bruta",v:fmt(profitOf(monthSales)),c:"#95d5b2"},
              {l:"Gastos",v:fmt(monthGastos.reduce((a,g)=>a+g.monto,0)),c:"#ff8787"},
              {l:"Lo que me quedó",v:fmt(profitOf(monthSales)-monthGastos.reduce((a,g)=>a+g.monto,0)),c:"#b2f2bb"},
              {l:"Margen promedio",v:`${totalOf(monthSales)>0?Math.round(profitOf(monthSales)/totalOf(monthSales)*100):0}%`},
            ].map((r,i,arr)=>(
              <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:i<arr.length-1?"1px solid rgba(255,255,255,0.1)":"none"}}>
                <span style={{color:"rgba(255,255,255,0.7)",fontSize:13}}>{r.l}</span>
                <span style={{fontWeight:700,color:r.c||"#ffffff",fontSize:14}}>{r.v}</span>
              </div>
            ))}
          </div>

          <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase",marginBottom:10}}>Comparación de ferias</div>
          {feriaStats.filter(f=>f.profileId===activeProfile).slice().sort((a,b)=>b.total-a.total).map(f=>(
            <div key={f.id} style={{...S.card,marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
                <span style={{fontSize:14,fontWeight:700,color:G.n100}}>{f.name}</span>
                <span style={{fontSize:14,color:"#212529",fontWeight:700}}>{fmt(f.total)}</span>
              </div>
              <div style={{background:G.n700,borderRadius:4,height:6,overflow:"hidden"}}>
                <div style={{background:`linear-gradient(90deg,${G.g600},${G.g400})`,height:"100%",borderRadius:4,
                  width:`${(()=>{const mx=Math.max(...feriaStats.filter(f=>f.profileId===activeProfile).map(x=>x.total),1);return(f.total/mx)*100;})()}%`,transition:"width 0.6s"}}/>
              </div>
              <div style={{fontSize:11,color:"#adb5bd",marginTop:6}}>{fechaL(f.startDate)} · {f.count} ventas · {fmt(f.profit)} gan.</div>
            </div>
          ))}

          {/* TOP PRODUCTOS */}
          {(() => {
            const prodCount = {};
            profSales.forEach(s=>{ prodCount[s.productName]=(prodCount[s.productName]||0)+(s.qty||1); });
            const top = Object.entries(prodCount).sort((a,b)=>b[1]-a[1]).slice(0,5);
            if(top.length===0) return null;
            return (
              <div style={{marginBottom:16}}>
                <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontWeight:600}}>Más vendidos del mes</div>
                <div style={{...S.card,padding:"12px 16px"}}>
                  {top.map(([name,qty],i)=>(
                    <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:i<top.length-1?"1px solid #f0f0f0":"none"}}>
                      <div style={{width:22,height:22,borderRadius:"50%",background:["#1b4332","#2d6a4f","#40916c","#52b788","#74c69d"][i],display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:"#fff",flexShrink:0}}>{i+1}</div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:12,fontWeight:600,color:"#212529",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{name}</div>
                      </div>
                      <div style={{fontSize:13,fontWeight:700,color:"#40916c",flexShrink:0}}>{qty} u.</div>
                      <div style={{width:60,height:6,background:"#f0f0f0",borderRadius:3,flexShrink:0}}>
                        <div style={{width:`${Math.round(qty/top[0][1]*100)}%`,height:"100%",background:"#40916c",borderRadius:3}}/>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })()}

          {/* VENTAS POR HORA */}
          {(() => {
            if(profSales.length===0) return null;
            const hours = Array(24).fill(0);
            profSales.forEach(s=>{ const h=new Date(s.date).getHours(); hours[h]+=s.total; });
            const maxH = Math.max(...hours);
            if(maxH===0) return null;
            const active = hours.map((v,h)=>({h,v})).filter(x=>x.v>0);
            return (
              <div style={{marginBottom:16}}>
                <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase",marginBottom:10,fontWeight:600}}>Ventas por hora</div>
                <div style={{...S.card,padding:"14px 16px"}}>
                  <div style={{display:"flex",alignItems:"flex-end",gap:4,height:60}}>
                    {active.map(({h,v})=>(
                      <div key={h} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
                        <div style={{width:"100%",background:"#40916c",borderRadius:"4px 4px 0 0",height:`${Math.round(v/maxH*52)+8}px`,opacity:0.7+0.3*(v/maxH)}}/>
                        <div style={{fontSize:9,color:"#adb5bd"}}>{h}h</div>
                      </div>
                    ))}
                  </div>
                  {(()=>{const top=[...active].sort((a,b)=>b.v-a.v)[0]; return top?(
                    <div style={{fontSize:11,color:"#868e96",marginTop:8,textAlign:"center"}}>
                      Hora pico: {top.h}hs · {fmt(top.v)}
                    </div>
                  ):null;})()}
                </div>
              </div>
            );
          })()}

          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:16,marginBottom:10}}>
            <div style={{fontSize:10,color:"#adb5bd",letterSpacing:2,textTransform:"uppercase"}}>Historial de ventas</div>
            <div style={{fontSize:11,color:"#adb5bd"}}>{profSales.length} registros</div>
          </div>
          <div style={{position:"relative",marginBottom:12}}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#adb5bd" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
              style={{position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",pointerEvents:"none"}}>
              <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
            </svg>
            <input value={ventaSearch} onChange={e=>setVentaSearch(e.target.value)}
              placeholder="Buscar por producto o cliente..."
              style={{width:"100%",background:"#fff",border:"1.5px solid #dee2e6",borderRadius:12,padding:"11px 14px 11px 38px",fontSize:13,outline:"none",boxSizing:"border-box",fontFamily:"inherit",color:"#212529"}}/>
            {ventaSearch&&<button onClick={()=>setVentaSearch("")} style={{position:"absolute",right:12,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:"#adb5bd",cursor:"pointer",fontSize:18,padding:0}}>×</button>}
          </div>
          {profSales.length===0&&<div style={{color:"#adb5bd",fontSize:14,textAlign:"center",marginTop:20}}>Sin ventas registradas</div>}
          {profSales.slice().reverse().filter(s=>!ventaSearch||s.productName?.toLowerCase().includes(ventaSearch.toLowerCase())||(s.clienteNombre||"").toLowerCase().includes(ventaSearch.toLowerCase())).map(s=>(
            <div key={s.id} style={{...S.card,marginBottom:8,padding:"12px 14px"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",cursor:"pointer"}}
                onClick={()=>setDetalleSale(detalleSale?.id===s.id?null:s)}>
                <div style={{flex:1,minWidth:0,marginRight:10}}>
                  <div style={{fontSize:12,fontWeight:600,color:"#212529",lineHeight:1.3}}>{s.productName}</div>
                  <div style={{fontSize:11,color:"#adb5bd",marginTop:3}}>{fechaL(s.date)} · {new Date(s.date).toLocaleTimeString("es-AR",{hour:"2-digit",minute:"2-digit"})} · {s.qty} u.</div>
                </div>
                <div style={{textAlign:"right",flexShrink:0,display:"flex",alignItems:"center",gap:8}}>
                  <div>
                    <div style={{fontSize:14,fontWeight:700,color:"#212529"}}>{fmt(s.total)}</div>
                    <div style={{fontSize:11,color:"#2d6a4f"}}>+{fmt(s.profit)}</div>
                  </div>
                  <div style={{fontSize:14,color:"#adb5bd"}}>{detalleSale?.id===s.id?"▲":"▼"}</div>
                </div>
              </div>
              {detalleSale?.id===s.id && (
                <div style={{background:"#f0fff4",borderRadius:10,padding:"12px 14px",margin:"10px 0 4px",border:"1px solid #b7e4c7"}}>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
                    {[
                      {l:"Precio venta",v:fmt(s.price),c:"#212529"},
                      {l:"Costo",v:fmt(s.cost),c:"#868e96"},
                      {l:"Ganancia",v:fmt(s.profit),c:"#2d6a4f"},
                      {l:"Margen",v:`${s.total>0?Math.round(s.profit/s.total*100):0}%`,c:"#2d6a4f"},
                    ].map((r,i)=>(
                      <div key={i} style={{background:"#ffffff",borderRadius:8,padding:"8px 10px",border:"1px solid #e9ecef"}}>
                        <div style={{fontSize:9,color:"#868e96",textTransform:"uppercase",letterSpacing:1,marginBottom:3}}>{r.l}</div>
                        <div style={{fontSize:16,fontWeight:800,color:r.c}}>{r.v}</div>
                      </div>
                    ))}
                  </div>
                  {s.metodoPago&&<div style={{fontSize:11,color:"#868e96"}}>Método: {s.metodoPago}</div>}
                </div>
              )}
              <div style={{display:"flex",gap:8,marginTop:10}}>
                <button onClick={()=>{
                  const html=generarComprobante(
                    {items:[{nombre:s.productName,precio:s.price,qty:s.qty,descripcion:""}],descuento:0,metodoPago:s.metodoPago||"Efectivo"},
                    {nombre:s.clienteNombre||"Cliente"},
                    LOGO_B64
                  );
                  setShowComprobante({html,tel:s.clienteTel||"",nombre:s.clienteNombre||"Cliente"});
                  setTab("ticket");
                }} style={{flex:1,background:"#2d6a4f",border:"none",borderRadius:8,padding:"7px",color:"#ffffff",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>
                  🧾 Comprobante
                </button>
                <button onClick={()=>setShowEditSale({...s})} style={{flex:1,background:G.n700,border:"none",borderRadius:8,padding:"7px",color:"#495057",fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
                  Editar
                </button>
                <button onClick={()=>setConfirmDeleteSale(s)} style={{flex:1,background:"rgba(192,57,43,0.15)",border:`1px solid ${G.red}33`,borderRadius:8,padding:"7px",color:G.red,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>
                  Eliminar
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
      </div>

      {/* ══════ MODALS ══════ */}

      {showNewFeria && <Modal onClose={()=>setShowNewFeria(false)} title="Nueva feria">
        <div style={{fontSize:12,color:"#adb5bd",marginBottom:12}}>📅 Hoy · {profile?.name}</div>
        <input placeholder="Nombre de la feria..." value={feriaName} onChange={e=>setFeriaName(e.target.value)} style={S.inp} autoFocus/>
        <button onClick={startFeria} style={S.btnPrimary}>Iniciar feria</button>
        <button onClick={()=>setShowNewFeria(false)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {showAddSub && <Modal onClose={()=>setShowAddSub(false)} title="Nuevo subgrupo">
        <input placeholder="Nombre" value={newSubName} onChange={e=>setNewSubName(e.target.value)} style={S.inp}/>
        <button onClick={()=>{
          if(!newSubName.trim())return showToast("Escribí un nombre","err");
          const ns={id:`sub-${Date.now()}`,name:newSubName.trim(),variants:[]};
          const{cat,group}=catNav;
          setCatalog(prev=>prev.map(c=>{
            if(c.id!==cat.id)return c;
            if(group)return{...c,groups:c.groups.map(g=>g.id!==group.id?g:{...g,subs:[...g.subs,ns]})};
            return{...c,subs:[...(c.subs||[]),ns]};
          }));
          setNewSubName("");setShowAddSub(false);showToast("Subgrupo creado");
        }} style={S.btnPrimary}>Crear</button>
        <button onClick={()=>setShowAddSub(false)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {showAddVariant && <Modal onClose={()=>setShowAddVariant(false)} title={`Nueva variante · ${catNav.sub?.name}`}>
        <input placeholder="Nombre de la variante" value={newVariant.name} onChange={e=>setNewVariant(v=>({...v,name:e.target.value}))} style={S.inp}/>
        <input type="number" placeholder="Costo ($)" value={newVariant.cost} onChange={e=>setNewVariant(v=>({...v,cost:e.target.value}))} style={S.inp}/>
        <input type="number" placeholder="Precio de venta ($)" value={newVariant.price} onChange={e=>setNewVariant(v=>({...v,price:e.target.value}))} style={S.inp}/>
        {newVariant.cost&&newVariant.price&&<div style={{...S.cardGreen,marginBottom:10}}>
          <div style={{display:"flex",justifyContent:"space-between"}}>
            <span style={{fontSize:13,color:G.n400}}>Margen</span>
            <span style={{fontWeight:700,color:G.g400}}>{pct(Number(newVariant.cost),Number(newVariant.price))}% · {fmt(Number(newVariant.price)-Number(newVariant.cost))}</span>
          </div>
        </div>}
        <input placeholder="Colores (Negro, Borravino, ...) — dejar vacío si no aplica" value={newVariant.colors} onChange={e=>setNewVariant(v=>({...v,colors:e.target.value}))} style={S.inp}/>
        <div style={{fontSize:11,color:"#adb5bd",marginBottom:14}}>Separar colores con coma. Dejar vacío para variante sin color.</div>
        <button onClick={()=>{
          if(!newVariant.name||!newVariant.cost||!newVariant.price)return showToast("Completá todos los campos","err");
          const colors=newVariant.colors?newVariant.colors.split(",").map(c=>c.trim()).filter(Boolean):[];
          const nv={id:`var-${Date.now()}`,name:newVariant.name.trim(),cost:Number(newVariant.cost),price:Number(newVariant.price),colors};
          const{cat,group,sub}=catNav;
          setCatalog(prev=>prev.map(c=>{
            if(c.id!==cat.id)return c;
            if(group)return{...c,groups:c.groups.map(g=>g.id!==group.id?g:{...g,subs:g.subs.map(s=>s.id!==sub.id?s:{...s,variants:[...(s.variants||[]),nv]})})};
            return{...c,subs:(c.subs||[]).map(s=>s.id!==sub.id?s:{...s,variants:[...(s.variants||[]),nv]})};
          }));
          setNewVariant({name:"",cost:"",price:"",colors:""});setShowAddVariant(false);showToast("Variante agregada");
        }} style={S.btnPrimary}>Guardar</button>
        <button onClick={()=>setShowAddVariant(false)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {showEditVariant && <Modal onClose={()=>setShowEditVariant(null)} title="Editar variante">
        <input value={showEditVariant.name} onChange={e=>setShowEditVariant(v=>({...v,name:e.target.value}))} style={S.inp}/>
        <input type="number" value={showEditVariant.cost} onChange={e=>setShowEditVariant(v=>({...v,cost:e.target.value}))} style={S.inp}/>
        <input type="number" value={showEditVariant.price} onChange={e=>setShowEditVariant(v=>({...v,price:e.target.value}))} style={S.inp}/>
        {showEditVariant.cost&&showEditVariant.price&&<div style={{...S.cardGreen,marginBottom:10}}>
          <div style={{display:"flex",justifyContent:"space-between"}}>
            <span style={{fontSize:13,color:G.n400}}>Margen</span>
            <span style={{fontWeight:700,color:G.g400}}>{pct(Number(showEditVariant.cost),Number(showEditVariant.price))}% · {fmt(Number(showEditVariant.price)-Number(showEditVariant.cost))}</span>
          </div>
        </div>}
        <input value={(showEditVariant.colors||[]).join(", ")} onChange={e=>setShowEditVariant(v=>({...v,colors:e.target.value.split(",").map(c=>c.trim()).filter(Boolean)}))} style={S.inp} placeholder="Colores separados por coma"/>
        <button onClick={()=>{
          const updated={...showEditVariant,cost:Number(showEditVariant.cost),price:Number(showEditVariant.price)};
          setCatalog(prev=>prev.map(c=>({...c,
            groups:c.groups?c.groups.map(g=>({...g,subs:g.subs.map(s=>({...s,variants:(s.variants||[]).map(v=>v.id===updated.id?updated:v)}))})):null,
            subs:(c.subs||[]).map(s=>({...s,variants:(s.variants||[]).map(v=>v.id===updated.id?updated:v)})),
          })));
          setShowEditVariant(null);showToast("Guardado");
        }} style={S.btnPrimary}>Guardar cambios</button>
        <button onClick={()=>{
          setCatalog(prev=>prev.map(c=>({...c,
            groups:c.groups?c.groups.map(g=>({...g,subs:g.subs.map(s=>({...s,variants:(s.variants||[]).filter(v=>v.id!==showEditVariant.id)}))})):null,
            subs:(c.subs||[]).map(s=>({...s,variants:(s.variants||[]).filter(v=>v.id!==showEditVariant.id)})),
          })));
          setShowEditVariant(null);showToast("Eliminado");
        }} style={{...S.btnGhost,color:G.red,borderColor:G.red}}>Eliminar variante</button>
        <button onClick={()=>setShowEditVariant(null)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {showGasto && <Modal onClose={()=>setShowGasto(false)} title="Registrar gasto">
        <input placeholder="Descripción" value={gastoForm.desc} onChange={e=>setGastoForm(g=>({...g,desc:e.target.value}))} style={S.inp}/>
        <select value={gastoForm.cat} onChange={e=>setGastoForm(g=>({...g,cat:e.target.value}))} style={{...S.inp, appearance:"none"}}>
          {GASTO_CATS.map(c=><option key={c}>{c}</option>)}
        </select>
        <input type="number" placeholder="Monto ($)" value={gastoForm.monto} onChange={e=>setGastoForm(g=>({...g,monto:e.target.value}))} style={S.inp}/>
        <button onClick={addGasto} style={{...S.btnPrimary,background:G.red}}>Registrar gasto</button>
        <button onClick={()=>setShowGasto(false)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {showPapeleria && <Modal onClose={()=>setShowPapeleria(false)} title="Costos de Papelería">
        {papeleria.map((p,i)=>(
          <div key={i} style={{display:"flex",gap:8,marginBottom:8}}>
            <select value={p.item} onChange={e=>{const n=[...papeleria];n[i]={...n[i],item:e.target.value};setPapeleria(n);}} style={{...S.inp,marginBottom:0,flex:2}}>
              {["Bolsa freeselina","Bolsa camiseta","Etiqueta","Papel tissue","Cinta","Otro"].map(it=><option key={it}>{it}</option>)}
            </select>
            <input type="number" placeholder="$" value={p.costo} onChange={e=>{const n=[...papeleria];n[i]={...n[i],costo:e.target.value};setPapeleria(n);}} style={{...S.inp,marginBottom:0,flex:1}}/>
            <button onClick={()=>setPapeleria(papeleria.filter((_,j)=>j!==i))} style={{background:"transparent",border:`1px solid ${G.n700}`,color:G.red,borderRadius:8,padding:"8px",cursor:"pointer",fontSize:16}}>×</button>
          </div>
        ))}
        <button onClick={()=>setPapeleria([...papeleria,{item:"Bolsa freeselina",costo:""}])} style={{...S.btnGhost,marginTop:0,marginBottom:10,fontSize:13}}>+ Agregar ítem</button>
        <div style={{...S.cardGreen,marginBottom:14}}>
          <div style={{display:"flex",justifyContent:"space-between"}}>
            <span style={{color:"#868e96",fontSize:13}}>Total por venta</span>
            <span style={{color:"#2d6a4f",fontWeight:700}}>{fmt(papeleria.reduce((a,p)=>a+(Number(p.costo)||0),0))}</span>
          </div>
        </div>
        <button onClick={()=>setShowPapeleria(false)} style={S.btnPrimary}>Guardar</button>
      </Modal>}

      {showCombo && <Modal onClose={()=>setShowCombo(false)} title="Calculadora de combos">
        {comboItems.map((item,i)=>(
          <div key={i} style={{display:"flex",gap:8,marginBottom:8,alignItems:"center"}}>
            <select value={item.itemId} onChange={e=>{const n=[...comboItems];n[i]={...n[i],itemId:e.target.value};setComboItems(n);}} style={{...S.inp,marginBottom:0,flex:3}}>
              <option value="">— Elegí —</option>
              {allItems.map(it=><option key={it.id} value={it.id}>{it.name} · {fmt(it.price)}</option>)}
            </select>
            <input type="number" min={1} value={item.qty} onChange={e=>{const n=[...comboItems];n[i]={...n[i],qty:Number(e.target.value)||1};setComboItems(n);}} style={{...S.inp,marginBottom:0,flex:1,textAlign:"center"}}/>
            {comboItems.length>1&&<button onClick={()=>setComboItems(comboItems.filter((_,j)=>j!==i))} style={{background:"transparent",border:`1px solid ${G.n700}`,color:G.red,borderRadius:8,padding:"8px",cursor:"pointer",fontSize:16}}>×</button>}
          </div>
        ))}
        <button onClick={()=>setComboItems([...comboItems,{itemId:"",qty:1}])} style={{...S.btnGhost,marginTop:0,marginBottom:12,fontSize:13}}>+ Agregar producto</button>
        <span style={S.label}>Costos extra</span>
        {comboExtras.map((e,i)=>(
          <div key={i} style={{display:"flex",gap:8,marginBottom:8}}>
            <input placeholder="Descripción" value={e.desc} onChange={ev=>{const n=[...comboExtras];n[i]={...n[i],desc:ev.target.value};setComboExtras(n);}} style={{...S.inp,marginBottom:0,flex:2}}/>
            <input type="number" placeholder="$" value={e.cost} onChange={ev=>{const n=[...comboExtras];n[i]={...n[i],cost:ev.target.value};setComboExtras(n);}} style={{...S.inp,marginBottom:0,flex:1}}/>
            {comboExtras.length>1&&<button onClick={()=>setComboExtras(comboExtras.filter((_,j)=>j!==i))} style={{background:"transparent",border:`1px solid ${G.n700}`,color:G.red,borderRadius:8,padding:"8px",cursor:"pointer",fontSize:16}}>×</button>}
          </div>
        ))}
        <button onClick={()=>setComboExtras([...comboExtras,{desc:"",cost:""}])} style={{...S.btnGhost,marginTop:0,marginBottom:12,fontSize:13}}>+ Extra</button>
        <input type="number" placeholder="Precio de venta ($)" value={comboPrecio} onChange={e=>setComboPrecio(e.target.value)} style={S.inp}/>
        <div style={{...S.cardGreen,borderColor:comboGan()>=0?G.g700:G.red}}>
          {[["Costo total",fmt(comboCosto()),G.n300],["Precio venta",fmt(Number(comboPrecio)),G.white],["Ganancia",fmt(comboGan()),comboGan()>=0?G.g400:G.red],["Margen",`${comboMgn()}%`,comboGan()>=0?G.g400:G.red]].map(([l,v,col])=>(
            <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${G.n700}`}}>
              <span style={{fontSize:13,color:G.n400}}>{l}</span>
              <span style={{fontSize:14,fontWeight:700,color:col}}>{v}</span>
            </div>
          ))}
        </div>
        <button onClick={()=>setShowCombo(false)} style={S.btnGhost}>Cerrar</button>
      </Modal>}

      {/* COBRANZA */}




      {/* CLIENTES */}
      {showClientes && <Modal onClose={()=>setShowClientes(false)} title="Base de clientes">
        {clientes.length===0&&<div style={{color:"#adb5bd",fontSize:14,textAlign:"center",margin:"20px 0"}}>Se guardan al generar un comprobante.</div>}
        {clientes.map(c=>(
          <div key={c.id} style={{...S.card,marginBottom:10}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
              <div>
                <div style={{fontSize:15,fontWeight:700,color:G.white}}>{c.nombre}</div>
                <div style={{fontSize:12,color:G.n500}}>📱 {c.tel||"Sin teléfono"}</div>
                <div style={{fontSize:11,color:"#adb5bd",marginTop:2}}>{(c.compras||[]).length} compras · {fmt((c.compras||[]).reduce((a,comp)=>a+comp.total,0))}</div>
              </div>
              {c.tel&&<button onClick={()=>window.open(`https://wa.me/${c.tel.replace(/\D/g,"")}?text=${encodeURIComponent(`¡Hola ${c.nombre}! 🧉`)}` ,"_blank")} style={{background:"#25D366",color:"#fff",border:"none",borderRadius:8,padding:"6px 12px",fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>WA</button>}
            </div>
            {(c.compras||[]).length>0&&(
              <div style={{marginTop:8,paddingTop:8,borderTop:"1px solid #f0f0f0"}}>
                <div style={{fontSize:10,color:"#adb5bd",textTransform:"uppercase",letterSpacing:1,marginBottom:6,fontWeight:600}}>Historial</div>
                {c.compras.slice(-3).reverse().map((comp,i)=>(
                  <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:11,color:"#868e96",marginBottom:3}}>
                    <span>{new Date(comp.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"2-digit"})}</span>
                    <span style={{fontWeight:600,color:"#212529"}}>{fmt(comp.total)}</span>
                  </div>
                ))}
                <div style={{fontSize:11,color:"#40916c",fontWeight:700,marginTop:4}}>
                  Total: {fmt(c.compras.reduce((a,cp)=>a+cp.total,0))} · {c.compras.length} compras
                </div>
              </div>
            )}
          </div>
        ))}
        <button onClick={()=>setShowClientes(false)} style={S.btnGhost}>Cerrar</button>
      </Modal>}

      {/* COMPROBANTE POST-VENTA — inline panel, no modal, so keyboard stays stable */}

      {/* EDITAR VENTA */}
      {showEditSale && <Modal onClose={()=>setShowEditSale(null)} title="Editar venta">
        <div style={{fontSize:12,color:"#adb5bd",marginBottom:12}}>{showEditSale.productName}</div>
        <span style={S.label}>Precio unitario ($)</span>
        <input type="number" value={showEditSale.price}
          onChange={e=>setShowEditSale(s=>({...s,price:Number(e.target.value),total:Number(e.target.value)*s.qty,profit:(Number(e.target.value)-s.cost)*s.qty}))}
          style={S.inp}/>
        <span style={S.label}>Cantidad</span>
        <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:14}}>
          <button onClick={()=>setShowEditSale(s=>({...s,qty:Math.max(1,s.qty-1),total:s.price*Math.max(1,s.qty-1),profit:(s.price-s.cost)*Math.max(1,s.qty-1)}))}
            style={{width:36,height:36,borderRadius:10,border:`1px solid ${G.n700}`,background:G.n800,color:"#212529",fontSize:18,cursor:"pointer"}}>−</button>
          <span style={{fontSize:22,fontWeight:800,minWidth:28,textAlign:"center",color:G.white}}>{showEditSale.qty}</span>
          <button onClick={()=>setShowEditSale(s=>({...s,qty:s.qty+1,total:s.price*(s.qty+1),profit:(s.price-s.cost)*(s.qty+1)}))}
            style={{width:36,height:36,borderRadius:10,border:`1px solid ${G.n700}`,background:G.n800,color:"#212529",fontSize:18,cursor:"pointer"}}>+</button>
        </div>
        <div style={{...S.cardGreen,marginBottom:14}}>
          <div style={{display:"flex",justifyContent:"space-between",padding:"4px 0"}}>
            <span style={{color:"#868e96",fontSize:13}}>Total</span>
            <span style={{color:"#212529",fontWeight:700}}>{fmt(showEditSale.price*showEditSale.qty)}</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",padding:"4px 0"}}>
            <span style={{color:"#868e96",fontSize:13}}>Ganancia</span>
            <span style={{color:"#2d6a4f",fontWeight:700}}>{fmt((showEditSale.price-showEditSale.cost)*showEditSale.qty)}</span>
          </div>
        </div>
        <button onClick={()=>{
          const updated={...showEditSale,total:showEditSale.price*showEditSale.qty,profit:(showEditSale.price-showEditSale.cost)*showEditSale.qty};
          setSales(prev=>prev.map(s=>s.id===updated.id?updated:s));
          setShowEditSale(null);showToast("Venta actualizada");
        }} style={S.btnPrimary}>Guardar cambios</button>
        <button onClick={()=>{
          setSales(prev=>prev.filter(s=>s.id!==showEditSale.id));
          setShowEditSale(null);showToast("Venta eliminada");
        }} style={{...S.btnGhost,color:G.red,borderColor:G.red,marginTop:8}}>🗑 Eliminar esta venta</button>
        <button onClick={()=>setShowEditSale(null)} style={S.btnGhost}>Cancelar</button>
      </Modal>}

      {/* CONFIRM DELETE SALE */}
      {confirmDeleteSale && <Modal onClose={()=>setConfirmDeleteSale(null)} title="Eliminar venta">
        <div style={{...S.card,marginBottom:16,textAlign:"center"}}>
          <div style={{fontSize:13,color:"#495057",lineHeight:1.5}}>{confirmDeleteSale.productName}</div>
          <div style={{fontSize:20,fontWeight:800,color:"#212529",marginTop:8}}>{fmt(confirmDeleteSale.total)}</div>
          <div style={{fontSize:11,color:"#adb5bd",marginTop:4}}>{fechaL(confirmDeleteSale.date)}</div>
        </div>
        <div style={{fontSize:13,color:"#868e96",textAlign:"center",marginBottom:16}}>
          ¿Confirmar eliminación? Esta acción no se puede deshacer.
        </div>
        <button onClick={()=>{
          setSales(prev=>prev.filter(s=>s.id!==confirmDeleteSale.id));
          setConfirmDeleteSale(null);
          showToast("Venta eliminada");
        }} style={{...S.btnPrimary,background:G.red,marginBottom:8}}>Sí, eliminar</button>
        <button onClick={()=>setConfirmDeleteSale(null)} style={S.btnGhost}>Cancelar</button>
      </Modal>}


      {/* ══════ COBRAR (inline, no modal) ══════ */}
      {tab==="cobrar" && (
        <div>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
            <button onClick={()=>setTab("inicio")} style={{background:"none",border:"none",color:"#868e96",cursor:"pointer",fontSize:20,padding:0}}>←</button>
            <div style={{fontSize:16,fontWeight:700,color:G.white}}>Generar comprobante</div>
          </div>

          <span style={S.label}>Datos del cliente</span>
          <input placeholder="Nombre y apellido *" value={cobrClienteNombre}
            onChange={e=>setCobrClienteNombre(e.target.value)}
            style={S.inp}/>
          <input placeholder="WhatsApp (ej: 2915356762)" type="tel" value={cobrClienteTel}
            onChange={e=>setCobrClienteTel(e.target.value)}
            style={S.inp}/>

          <span style={S.label}>Productos</span>
          {cobrItems.map((item,i)=>(
            <div key={i} style={{...S.card,marginBottom:10}}>
              <input placeholder="Nombre del producto" value={item.nombre}
                onChange={e=>{const n=[...cobrItems];n[i]={...n[i],nombre:e.target.value};setCobrItems(n);}}
                style={{...S.inp,marginBottom:6}}/>
              <input placeholder="Descripción / detalle (opcional)" value={item.descripcion}
                onChange={e=>{const n=[...cobrItems];n[i]={...n[i],descripcion:e.target.value};setCobrItems(n);}}
                style={{...S.inp,marginBottom:6}}/>
              <div style={{display:"flex",gap:8}}>
                <input type="number" placeholder="$ precio unit." value={item.precio}
                  onChange={e=>{const n=[...cobrItems];n[i]={...n[i],precio:e.target.value};setCobrItems(n);}}
                  style={{...S.inp,marginBottom:0,flex:2}}/>
                <div style={{display:"flex",alignItems:"center",gap:6,flex:1}}>
                  <button onClick={()=>{const n=[...cobrItems];n[i]={...n[i],qty:Math.max(1,n[i].qty-1)};setCobrItems(n);}}
                    style={{width:30,height:30,borderRadius:8,border:`1px solid ${G.n700}`,background:G.n700,color:"#212529",fontSize:16,cursor:"pointer"}}>−</button>
                  <span style={{fontSize:15,fontWeight:700,minWidth:16,textAlign:"center",color:G.white}}>{item.qty}</span>
                  <button onClick={()=>{const n=[...cobrItems];n[i]={...n[i],qty:n[i].qty+1};setCobrItems(n);}}
                    style={{width:30,height:30,borderRadius:8,border:`1px solid ${G.n700}`,background:G.n700,color:"#212529",fontSize:16,cursor:"pointer"}}>+</button>
                </div>
                {cobrItems.length>1&&<button onClick={()=>setCobrItems(cobrItems.filter((_,j)=>j!==i))}
                  style={{background:"transparent",border:`1px solid ${G.n700}`,color:G.red,borderRadius:8,padding:"6px 10px",cursor:"pointer",fontSize:14}}>×</button>}
              </div>
            </div>
          ))}
          <button onClick={()=>setCobrItems([...cobrItems,{nombre:"",descripcion:"",precio:"",qty:1}])}
            style={{...S.btnGhost,marginTop:0,marginBottom:14,fontSize:13}}>+ Agregar producto</button>

          <span style={S.label}>Descuento (opcional)</span>
          <div style={{display:"flex",gap:8,marginBottom:10}}>
            {[["pct","% Porcentaje"],["monto","$ Monto"]].map(([m,l])=>(
              <button key={m} onClick={()=>{setCobrMode(m);setCobrDescPct("");setCobrDescMonto("");}}
                style={{flex:1,padding:"8px",borderRadius:8,border:`1px solid ${cobrMode===m?G.g600:G.n700}`,
                  background:cobrMode===m?G.g900:G.n800,color:cobrMode===m?G.g400:G.n400,
                  cursor:"pointer",fontFamily:"inherit",fontSize:12,fontWeight:cobrMode===m?700:400}}>
                {l}
              </button>
            ))}
          </div>
          {cobrMode==="pct"?(
            <div style={{display:"flex",gap:8}}>
              <input type="number" placeholder="% descuento" value={cobrDescPct}
                onChange={e=>{setCobrDescPct(e.target.value);setCobrDescMonto(Math.round(cobrTotal*(Number(e.target.value)||0)/100).toString());}}
                style={{...S.inp,flex:1}}/>
              <div style={{...S.cardGreen,flex:1,marginBottom:0,display:"flex",flexDirection:"column",justifyContent:"center"}}>
                <div style={{fontSize:10,color:G.n500}}>Descuento</div>
                <div style={{fontSize:14,fontWeight:700,color:G.red}}>{fmt(cobrDescVal)}</div>
              </div>
            </div>
          ):(
            <div style={{display:"flex",gap:8}}>
              <input type="number" placeholder="$ descuento" value={cobrDescMonto}
                onChange={e=>{setCobrDescMonto(e.target.value);setCobrDescPct(cobrTotal>0?Math.round((Number(e.target.value)||0)/cobrTotal*100).toString():"");}}
                style={{...S.inp,flex:1}}/>
              <div style={{...S.cardGreen,flex:1,marginBottom:0,display:"flex",flexDirection:"column",justifyContent:"center"}}>
                <div style={{fontSize:10,color:G.n500}}>Porcentaje</div>
                <div style={{fontSize:14,fontWeight:700,color:G.g400}}>{cobrPctCalc}%</div>
              </div>
            </div>
          )}

          <div style={{...S.cardGreen,marginTop:14,marginBottom:16}}>
            {cobrDescVal>0&&<>
              <div style={{display:"flex",justifyContent:"space-between",padding:"4px 0"}}>
                <span style={{color:"#868e96",fontSize:13}}>Subtotal</span>
                <span style={{fontSize:13,color:G.n200}}>{fmt(cobrTotal)}</span>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",padding:"4px 0"}}>
                <span style={{color:G.red,fontSize:13}}>Descuento</span>
                <span style={{color:G.red,fontSize:13}}>-{fmt(cobrDescVal)}</span>
              </div>
            </>}
            <div style={{display:"flex",justifyContent:"space-between",padding:"10px 0 0",borderTop:`1px solid ${G.g800}`}}>
              <span style={{fontSize:15,fontWeight:700,color:G.white}}>Total</span>
              <span style={{fontSize:20,fontWeight:800,color:G.g400}}>{fmt(cobrFinal)}</span>
            </div>
          </div>

          <span style={S.label}>Método de pago</span>
          <div style={{display:"flex",gap:8,marginBottom:16}}>
            {["Efectivo","Transferencia"].map(m=>(
              <button key={m} onClick={()=>setMetodoPago(m)}
                style={{flex:1,padding:"13px",borderRadius:12,border:`1.5px solid ${metodoPago===m?"#40916c":"#dee2e6"}`,
                  background:metodoPago===m?"#40916c":"#ffffff",color:metodoPago===m?"#ffffff":"#868e96",
                  cursor:"pointer",fontFamily:"inherit",fontSize:14,fontWeight:metodoPago===m?700:500,
                  display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
                {m==="Efectivo"
                  ?<><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="6" width="20" height="12" rx="2"/><circle cx="12" cy="12" r="2"/></svg> Efectivo</>
                  :<><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="5" y="2" width="14" height="20" rx="2"/><line x1="12" y1="18" x2="12.01" y2="18"/></svg> Transferencia</>}
              </button>
            ))}
          </div>

          <input value={cobrNota} onChange={e=>setCobrNota(e.target.value)}
            placeholder="📝 Nota interna (opcional)..."
            style={{...S.inp,marginBottom:12,fontSize:13}}/>
          <button onClick={generarYEnviar} style={S.btnPrimary}>Generar comprobante</button>
          <button onClick={()=>setTab("inicio")} style={S.btnGhost}>Cancelar</button>
        </div>
      )}


      {/* ══════ TICKET (inline) ══════ */}
      {tab==="ticket" && showComprobante && (
        <TicketScreen
          comprobante={showComprobante}
          onBack={()=>setTab("inicio")}
          G={G}
          S={S}
        />
      )}

      {/* BOTTOM NAV */}
      <div style={{ position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)", width:"100%",
        maxWidth:420, background:"#ffffff", borderTop:"1px solid #e9ecef", boxShadow:"0 -2px 12px rgba(0,0,0,0.06)",
        display:"flex", padding:"6px 8px 16px" }}>
        {tabs.map(t => <TabBtn key={t.id} {...t}/>)}
      </div>
    </div>
  );
}
